  type: ProcessStepType;
  onAdd: (type: ProcessStepType) => void;
}

const PaletteItem: React.FC<PaletteItemProps> = ({ type, onAdd }) => {
  const { icon: Icon, color, defaultName: label } = getStepTypeMetadata(type);

  const onDragStart = (event: React.DragEvent, nodeType: string) => {
    event.dataTransfer.setData('application/reactflow', nodeType);
    event.dataTransfer.effectAllowed = 'move';
  };

  return (
    <div 
      className="flex items-center group relative"
      draggable 
      onDragStart={(e) => onDragStart(e, type)}
    >
        <button 
        onClick={() => onAdd(type)} 
        className="w-full flex items-center gap-3 p-2 bg-white hover:bg-slate-50 border border-transparent hover:border-slate-200 rounded-sm text-left transition-all cursor-grab active:cursor-grabbing"
        >
        <div className={`w-8 h-8 rounded-sm flex items-center justify-center shrink-0 bg-slate-50 border border-slate-200 group-hover:bg-white group-hover:border-blue-400`}>
            <Icon size={16} className={`${color} group-hover:text-blue-600`} />
        </div>
        <div className="flex-1 min-w-0">
            <span className="block text-xs font-bold text-slate-700 truncate">{label}</span>
        </div>
        <Plus size={14} className="text-slate-300 group-hover:text-blue-50 opacity-0 group-hover:opacity-100" />
        </button>
    </div>
  );
};

export const PaletteSidebar = ({ onAddNode }: { onAddNode: (type: ProcessStepType) => void }) => {
  const [openCategories, setOpenCategories] = useState<string[]>(['Core', 'Communication', 'AI & ML']);
  const [search, setSearch] = useState('');

  const toggleCategory = (cat: string) => {
    setOpenCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]);
  };

  // Group steps by category based on metadata
  const groupedSteps: Record<string, ProcessStepType[]> = {};

  const allTypes: ProcessStepType[] = [
    // CORE
    'start', 'end', 'user-task', 'service-task', 'sub-process', 'script-task',
    // GATEWAYS
    'exclusive-gateway', 'parallel-gateway', 'inclusive-gateway', 'complex-gateway', 'event-gateway',
    // EVENTS
    'timer-event', 'message-event', 'signal-event', 'error-event', 'escalation-event', 'compensation-event',
    // COMMUNICATION
    'email-send', 'slack-post', 'teams-message', 'sms-twilio', 'whatsapp-msg', 'push-notification', 'sendgrid-email', 'mailchimp-add',
    // DOCUMENTS
    'pdf-generate', 'doc-sign', 'ocr-extract', 's3-upload', 'gdrive-save', 'sharepoint-store', 'dropbox-save', 'template-render',
    // CRM
    'salesforce-create', 'salesforce-update', 'hubspot-add', 'zoho-lead', 'pipedrive-deal', 'dynamics-record', 'zendesk-ticket', 'intercom-msg',
    // DEV
    'jira-issue', 'github-pr', 'gitlab-merge', 'bitbucket-commit', 'trello-card', 'asana-task', 'linear-issue', 'pagerduty-alert',
    // CLOUD
    'aws-lambda', 'azure-func', 'gcp-function', 'kubernetes-job', 'vm-provision', 'db-provision', 'dns-update', 'cdn-purge',
    // DATA
    'sql-query', 'rest-api', 'graphql-query', 'soap-call', 'kafka-publish', 'rabbit-mq', 'ftp-upload', 'csv-parse', 'xml-transform', 'json-map',
    // AI
    'ai-text-gen', 'ai-summarize', 'ai-sentiment', 'ai-vision', 'ai-translate', 'ai-classify', 'automl-predict', 'vector-embed',
    // FINANCE
    'stripe-charge', 'paypal-payout', 'quickbooks-invoice', 'xero-bill', 'sap-posting', 'oracle-ledger', 'expensify-report',
    // LOGIC
    'business-rule', 'decision-table', 'wait-state', 'terminate-end', 'loop-container'
  ];

  allTypes.forEach(type => {
    const meta = getStepTypeMetadata(type);
    if (!groupedSteps[meta.category]) groupedSteps[meta.category] = [];
    if (meta.defaultName.toLowerCase().includes(search.toLowerCase()) || meta.category.toLowerCase().includes(search.toLowerCase())) {
        groupedSteps[meta.category].push(type);
    }
  });

  return (
    <aside className="w-full h-full bg-slate-50 border-r border-slate-300 flex flex-col shrink-0">
      <div className="border-b border-slate-200" style={{ padding: 'var(--space-base)' }}>
        <h2 className="text-xs font-bold text-slate-800 uppercase tracking-wider mb-2">Component Library</h2>
        <div className="relative">
            <Search className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" size={12}/>
            <input 
                className="w-full pl-7 pr-2 py-1.5 bg-white border border-slate-300 rounded-sm text-xs outline-none focus:border-blue-500" 
                placeholder="Search components..."
                value={search}
                onChange={e => setSearch(e.target.value)}
            />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar" style={{ padding: 'var(--space-base)', gap: 'var(--space-base)', display: 'flex', flexDirection: 'column' }}>
        {STEP_CATEGORIES.map(category => {
            const steps = groupedSteps[category] || [];
            if (steps.length === 0) return null;

            const isOpen = openCategories.includes(category) || search.length > 0;

            return (
                <div key={category} className="mb-2">
                    <button 
                        onClick={() => toggleCategory(category)}
                        className="w-full flex items-center justify-between px-2 py-1.5 text-[10px] font-bold text-slate-500 uppercase hover:bg-slate-100 rounded-sm transition-colors"
                    >
                        <span>{category}</span>
                        {isOpen ? <ChevronDown size={12}/> : <ChevronRight size={12}/>}
                    </button>

                    {isOpen && (
                        <div className="mt-1 space-y-0.5 pl-1 animate-slide-up">
                            {steps.map(type => (
                                <PaletteItem key={type} type={type} onAdd={onAddNode} />
                            ))}
                        </div>
                    )}
                </div>
            );
        })}
      </div>
    </aside>
  );
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';

type Density = 'compact' | 'comfortable' | 'spacious';

interface ThemeContextType {
  scale: number;
  setScale: (n: number) => void;
  sidebarWidth: number;
  setSidebarWidth: (n: number) => void;
  headerHeight: number;
  setHeaderHeight: (n: number) => void;
  radius: number;
  setRadius: (n: number) => void;
  density: Density;
  setDensity: (d: Density) => void;
  resetTheme: () => void;
}

const defaultTheme = {
  scale: 1,
  sidebarWidth: 256,
  headerHeight: 56,
  radius: 2,
  density: 'comfortable' as Density
};

const ThemeContext = createContext<ThemeContextType | undefined>(undefined);

export const ThemeProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [scale, setScale] = useState(defaultTheme.scale);
  const [sidebarWidth, setSidebarWidth] = useState(defaultTheme.sidebarWidth);
  const [headerHeight, setHeaderHeight] = useState(defaultTheme.headerHeight);
  const [radius, setRadius] = useState(defaultTheme.radius);
  const [density, setDensity] = useState<Density>(defaultTheme.density);

  useEffect(() => {
    const root = document.documentElement;

    // 1. Global Scale (Affects rem units: padding, margin, font-size)
    root.style.fontSize = `${scale * 100}%`; 

    // 2. Layout Dimensions
    root.style.setProperty('--sidebar-width', `${sidebarWidth}px`);
    root.style.setProperty('--header-height', `${headerHeight}px`);

    // 3. Component Styling
    root.style.setProperty('--radius-base', `${radius}px`);
    root.style.setProperty('--component-bg', '#ffffff');

    // 4. Density & Spacing
    const densityMap = {
      compact: { 
        space: '0.5rem', 
        text: '12px',
        padding: '16px',
        gap: '12px',
        cardPadding: '12px',
        sectionGap: '16px'
      },
      comfortable: { 
        space: '0.75rem', 
        text: '13px', 
        padding: '32px', 
        gap: '24px',
        cardPadding: '20px',
        sectionGap: '32px'
      },
      spacious: { 
        space: '1.25rem', 
        text: '14px', 
        padding: '48px', 
        gap: '40px',
        cardPadding: '32px',
        sectionGap: '48px'
      }
    };

    const d = densityMap[density];
    root.style.setProperty('--space-base', d.space);
    root.style.setProperty('--text-base', d.text);
    root.style.setProperty('--layout-padding', d.padding);
    root.style.setProperty('--layout-gap', d.gap);
    root.style.setProperty('--card-padding', d.cardPadding);
    root.style.setProperty('--section-gap', d.sectionGap);

  }, [scale, sidebarWidth, headerHeight, radius, density]);

  const resetTheme = () => {
    setScale(defaultTheme.scale);
    setSidebarWidth(defaultTheme.sidebarWidth);
    setHeaderHeight(defaultTheme.headerHeight);
    setRadius(defaultTheme.radius);
    setDensity(defaultTheme.density);
  };

  return (
    <ThemeContext.Provider value={{
      scale, setScale,
      sidebarWidth, setSidebarWidth,
      headerHeight, setHeaderHeight,
      radius, setRadius,
      density, setDensity,
      resetTheme
    }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => {
  const context = useContext(ThemeContext);
  if (!context) throw new Error("useTheme must be used within a ThemeProvider");
  return context;
};

import React, { memo, useMemo } from 'react';
import { Handle, Position, NodeProps } from 'reactflow';
import { ProcessStep } from '../../types';
import { getStepTypeMetadata } from './designerUtils';
import { FunctionSquare, RefreshCw, Code, AlertCircle, Layers, ShieldAlert } from 'lucide-react';
import { validateStepConfiguration } from './stepSchemas';

// Define the custom data interface
interface CustomNodeData {
  step: ProcessStep;
  // We can pass visual flags via data if needed, but 'selected' comes from props
}

// React Flow passes `selected` as a direct prop to custom nodes
export const NodeComponent = memo(({ data, selected }: NodeProps<CustomNodeData>) => {
  const { step } = data;
  const { icon: Icon, color } = getStepTypeMetadata(step.type);

  // Logic Detection
  const hasRule = !!step.businessRuleId;
  const hasScript = !!step.onEntryAction || !!step.onExitAction;
  const hasRetry = step.retryPolicy?.enabled;
  const isLoop = step.isMultiInstance;

  // Guard Validation: Check if the step meets its schema requirements
  const isValid = useMemo(() => validateStepConfiguration(step.type, step.data), [step.type, step.data]);

  return (
    <div 
      className={`w-[200px] h-[80px] border flex flex-col shadow-sm transition-shadow select-none group ${
        selected 
          ? 'border-active ring-2 ring-blue-500/20 shadow-md' 
          : (isValid ? 'border-default hover:border-tertiary' : 'border-rose-300 ring-1 ring-rose-200')
      }`} 
      style={{ 
        borderRadius: 'var(--radius-base)',
        backgroundColor: 'var(--component-bg)',
      }}
    >
      {/* React Flow Handles */}
      <Handle 
        type="target" 
        position={Position.Left} 
        className="!bg-slate-400 !w-2.5 !h-2.5 !-left-1.5 hover:!bg-blue-600 transition-colors" 
        style={{ borderColor: 'var(--component-bg)', borderWidth: '2px' }}
      />

      {/* Main Body */}
      <div className="flex items-center gap-3 px-3 pt-3 pb-1 flex-1 overflow-hidden pointer-events-none">
        <div className={`w-8 h-8 flex items-center justify-center rounded-base bg-subtle border border-default relative shrink-0`}>
          <Icon size={16} className={color.replace('text-', 'text-opacity-80 text-')} />
          {!isValid && (
             <div className="absolute -top-1.5 -right-1.5 bg-white rounded-full p-0.5 shadow-sm" title="Invalid Configuration">
                <ShieldAlert size={14} className="text-rose-500 fill-rose-50"/>
             </div>
          )}
        </div>

        <div className="flex-1 min-w-0">
          <p className="text-[12px] font-bold text-primary truncate leading-tight">
            {step.name}
          </p>
          <p className="text-[10px] text-secondary uppercase tracking-wide truncate mt-0.5">
            {step.type.replace(/-/g, ' ')}
          </p>
        </div>
      </div>

      {/* Logic Badges Bar */}
      {(hasRule || hasScript || hasRetry || isLoop) && (
          <div className="px-3 pb-2 flex gap-1.5 items-center pointer-events-none">
              {hasRule && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-indigo-50 border border-indigo-100 rounded-[2px] text-[8px] font-bold text-indigo-700">
                      <FunctionSquare size={8} /> RULE
                  </div>
              )}
              {hasScript && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-amber-50 border border-amber-100 rounded-[2px] text-[8px] font-bold text-amber-700">
                      <Code size={8} /> FN
                  </div>
              )}
              {hasRetry && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-blue-50 border border-blue-100 rounded-[2px] text-[8px] font-bold text-blue-700">
                      <RefreshCw size={8} /> {step.retryPolicy?.maxAttempts}x
                  </div>
              )}
              {isLoop && (
                  <div className="ml-auto text-secondary">
                      <Layers size={10} />
                  </div>
              )}
          </div>
      )}

      <Handle 
        type="source" 
        position={Position.Right} 
        className="!bg-slate-400 !w-2.5 !h-2.5 !-right-1.5 hover:!bg-blue-600 transition-colors"
        style={{ borderColor: 'var(--component-bg)', borderWidth: '2px' }}
      />
    </div>
  );
});

import React from 'react';
import { BaseEdge, EdgeLabelRenderer, EdgeProps, getSmoothStepPath } from 'reactflow';
import { X } from 'lucide-react';
import { useBPM } from '../../contexts/BPMContext';

export const CustomEdge = ({
  id,
  sourceX,
  sourceY,
  targetX,
  targetY,
  sourcePosition,
  targetPosition,
  style = {},
  markerEnd,
  label,
  selected
}: EdgeProps) => {
  const { setDesignerDraft } = useBPM();
  // Using SmoothStep for orthogonal-like routing which is standard in BPMN
  const [edgePath, labelX, labelY] = getSmoothStepPath({
    sourceX,
    sourceY,
    sourcePosition,
    targetX,
    targetY,
    targetPosition,
  });

  // Function to delete edge (logic would typically be passed down or handled via context in full implementation)
  // For now, we rely on the parent selection deletion, but this demonstrates the UI capability
  const onEdgeClick = (evt: React.MouseEvent) => {
    evt.stopPropagation();
    // In a real implementation, we would dispatch a delete action here
    // For now, it selects the edge
  };

  return (
    <>
      <BaseEdge path={edgePath} markerEnd={markerEnd} style={{ ...style, strokeWidth: selected ? 2 : 1.5, stroke: selected ? '#2563eb' : '#64748b' }} />
      <EdgeLabelRenderer>
        <div
          style={{
            position: 'absolute',
            transform: `translate(-50%, -50%) translate(${labelX}px,${labelY}px)`,
            fontSize: 10,
            pointerEvents: 'all',
          }}
          className="nodrag nopan"
        >
          {label && (
            <div 
                className="px-2 py-1 border border-slate-200 shadow-sm text-slate-600 font-mono text-[9px]"
                style={{ 
                    backgroundColor: 'var(--component-bg)', 
                    borderRadius: 'var(--radius-base)' 
                }}
            >
              {label}
            </div>
          )}
          {selected && (
             <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-rose-500 text-white rounded-full p-0.5 shadow-sm cursor-pointer hover:scale-110 transition-transform" title="Delete Connection">
                 {/* This button is purely visual in this demo until we wire the delete handler directly */}
                 <X size={10} />
             </div>
          )}
        </div>
      </EdgeLabelRenderer>
    </>
  );
};

import React, { useState, useMemo } from 'react';
import { ProcessStep, UserRole, IOMapping, RetryPolicy, EscalationRule } from '../../types';
import { useBPM } from '../../contexts/BPMContext';
import { 
  Trash2, Compass, X, ExternalLink, 
  Settings, Database, RefreshCw, ArrowRightLeft, 
  Braces, ShieldAlert, Plus, Minimize2, Key, Sparkles, FunctionSquare, Layout, Clock, AlertCircle
} from 'lucide-react';
import { NexFormGroup } from '../shared/NexUI';
import { getStepTypeMetadata } from './designerUtils';
import { DataMapper } from '../shared/DataMapper';
import { STEP_SCHEMAS, ConfigField } from './stepSchemas';

// Mock variables available in the process context
const PROCESS_VARS = [
    'request.id', 'request.amount', 'request.requester', 'request.date', 
    'approval.status', 'approval.comment', 
    'user.email', 'user.department',
    'system.timestamp', 'case.id'
];

// Mock inputs expected by various step types
const GET_TARGET_SCHEMA = (type: string): string[] => {
    // Generate target schema keys from the static schema definition
    const schema = STEP_SCHEMAS[type as any];
    if (schema) {
        return schema.map(f => f.key);
    }
    return ['config', 'input'];
};

export const PropertiesPanel = ({ 
  step, 
  onUpdate, 
  onDelete, 
  roles,
  onClose
}: { 
  step: ProcessStep | undefined; 
  onUpdate: (step: ProcessStep) => void; 
  onDelete: (id: string) => void; 
  roles: UserRole[]; 
  onClose?: () => void;
}) => {
    const { rules, forms, navigateTo } = useBPM();
    const [activeTab, setActiveTab] = useState<'config' | 'data' | 'logic' | 'policy'>('config');

    // Always call hooks regardless of step existence
    const panelWidthClass = useMemo(() => {
        if (!step) return 'w-[320px]';

        // Data Mapper needs wide view
        if (activeTab === 'data') return 'w-[600px]';

        // Logic with Scripts needs medium wide
        if (activeTab === 'logic' && (step.onEntryAction || step.onExitAction)) return 'w-[450px]';

        // Specific complex steps
        if (['script-task', 'pdf-generate', 'template-render', 'xml-transform', 'json-map', 'api-gateway', 'sql-query', 'graphql-query'].includes(step.type)) {
            return 'w-[480px]';
        }

        if (['sendgrid-email', 'email-send'].includes(step.type)) return 'w-[400px]';

        return 'w-[320px]';
    }, [step?.type, activeTab, step?.onEntryAction, step?.onExitAction]);

    // Safe derivations (handle undefined step)
    const meta = step ? getStepTypeMetadata(step.type) : { icon: Compass, color: 'text-slate-400', defaultName: '', category: '' };
    const schema = step ? (STEP_SCHEMAS[step.type] || []) : [];

    const updateField = (field: keyof ProcessStep, value: any) => { if (step) onUpdate({ ...step, [field]: value }); };
    const updateDataField = (key: string, value: any) => { if (step) onUpdate({ ...step, data: { ...step.data, [key]: value } }); };

    const updateEscalation = (field: keyof EscalationRule, value: any) => {
        if (!step) return;
        const current = step.escalation || { enabled: false, daysAfterDue: 1, action: 'notify_manager' };
        onUpdate({ ...step, escalation: { ...current, [field]: value } });
    };

    const updateRetry = (field: keyof RetryPolicy, value: any) => {
        if (!step) return;
        const current = step.retryPolicy || { enabled: false, maxAttempts: 3, strategy: 'fixed', delayMs: 1000 };
        onUpdate({ ...step, retryPolicy: { ...current, [field]: value } });
    };

    const renderDynamicField = (field: ConfigField) => {
        const value = step?.data?.[field.key] ?? field.defaultValue ?? '';

        switch(field.type) {
            case 'select':
                return (
                    <NexFormGroup key={field.key} label={field.label} helpText={field.helpText}>
                        <select className="prop-input" value={value} onChange={e => updateDataField(field.key, e.target.value)}>
                            {field.options?.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                        </select>
                    </NexFormGroup>
                );
            case 'textarea':
            case 'json':
            case 'code':
                return (
                    <NexFormGroup key={field.key} label={field.label} helpText={field.helpText}>
                        <textarea 
                            className={`prop-input min-h-[100px] resize-y ${field.type === 'code' || field.type === 'json' ? 'font-mono text-[10px]' : ''}`}
                            value={value} 
                            onChange={e => updateDataField(field.key, e.target.value)} 
                            placeholder={field.placeholder}
                        />
                    </NexFormGroup>
                );
            case 'boolean':
                return (
                    <div key={field.key} className="mb-4 flex items-center justify-between">
                        <label className="prop-label mb-0">{field.label}</label>
                        <input type="checkbox" checked={!!value} onChange={e => updateDataField(field.key, e.target.checked)} className="rounded-sm text-blue-600 focus:ring-blue-500" />
                    </div>
                );
            default:
                return (
                    <NexFormGroup key={field.key} label={field.label} helpText={field.helpText}>
                        <input 
                            type={field.type === 'number' ? 'number' : 'text'}
                            className="prop-input" 
                            value={value} 
                            onChange={e => updateDataField(field.key, e.target.value)} 
                            placeholder={field.placeholder}
                        />
                    </NexFormGroup>
                );
        }
    };

    return (
      <aside className={`${panelWidthClass} h-full bg-white border-l border-slate-300 flex flex-col shadow-xl z-20 transition-all duration-300 ease-in-out`}>
        {!step ? (
            <div className="flex-1 flex flex-col items-center justify-center text-center p-8">
                <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4 border border-slate-200">
                    <Compass size={32} strokeWidth={1} className="text-slate-300" />
                </div>
                <h3 className="text-sm font-bold text-slate-800">Inspector</h3>
                <p className="text-xs text-slate-500 mt-2 max-w-[200px]">Select a component to configure properties.</p>
            </div>
        ) : (
            <>
            {/* Header */}
            <div 
            className="flex items-center justify-between border-b border-slate-300 bg-slate-50"
            style={{ height: 'var(--header-height)', paddingLeft: 'var(--space-base)', paddingRight: 'var(--space-base)' }}
            >
            <div className="flex items-center gap-2">
                <meta.icon size={14} className={meta.color} />
                <h3 className="text-xs font-bold text-slate-800 uppercase tracking-wider">{meta.category}</h3>
                <span className="text-[10px] text-slate-400 font-mono">| {step.type}</span>
            </div>
            <div className="flex items-center gap-2">
                <button onClick={() => onUpdate({ ...step, id: step.id } as any)} className="text-slate-400 hover:text-slate-800" title="Minimize/Refresh"><Minimize2 size={14}/></button>
                {onClose && <button onClick={onClose} className="text-slate-400 hover:text-slate-800"><X size={14}/></button>}
            </div>
            </div>

            {/* Identity Block (Always Visible) */}
            <div className="border-b border-slate-100 bg-white" style={{ padding: 'var(--card-padding)' }}>
                <input 
                type="text" 
                className="text-sm font-bold text-slate-900 w-full outline-none border-b border-transparent focus:border-blue-500 placeholder:text-slate-300 transition-all mb-1" 
                value={step.name} 
                onChange={e => updateField('name', e.target.value)}
                placeholder="Step Name"
                />
                <input 
                type="text"
                className="text-xs text-slate-500 w-full outline-none bg-transparent"
                value={step.description || ''}
                onChange={e => updateField('description', e.target.value)}
                placeholder="Add technical description..."
                />
            </div>

            {/* Tabs */}
            <div className="flex border-b border-slate-200 bg-slate-50/50">
                {[
                    { id: 'config', icon: Settings, label: 'Config' },
                    { id: 'data', icon: Database, label: 'Wiring' },
                    { id: 'logic', icon: FunctionSquare, label: 'Rules' },
                    { id: 'policy', icon: ShieldAlert, label: 'Policy' }
                ].map(tab => (
                    <button 
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id as any)}
                        className={`flex-1 py-2 flex items-center justify-center gap-1.5 text-[10px] font-bold uppercase transition-all border-b-2 ${activeTab === tab.id ? 'border-blue-600 text-blue-600 bg-white' : 'border-transparent text-slate-500 hover:bg-white hover:text-slate-700'}`}
                    >
                        <tab.icon size={12}/> {tab.label}
                    </button>
                ))}
            </div>

            <div className="flex-1 overflow-y-auto no-scrollbar bg-slate-50/30" style={{ padding: 'var(--card-padding)' }}>

            {/* TAB: CONFIGURATION (Dynamic based on type) */}
            {activeTab === 'config' && (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--layout-gap)' }}>
                    {/* User Task Specifics */}
                    {step.type === 'user-task' && (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--layout-gap)' }}>
                            <NexFormGroup label="User Interface">
                                <div className="flex items-center gap-2">
                                    <Layout size={16} className="text-slate-400"/>
                                    <select className="prop-input" value={step.formId || ''} onChange={e => updateField('formId', e.target.value)}>
                                        <option value="">Generic Task View</option>
                                        {forms.map(f => <option key={f.id} value={f.id}>{f.name}</option>)}
                                    </select>
                                </div>
                                {step.formId && <button onClick={() => navigateTo('form-designer', step.formId)} className="text-[10px] text-blue-600 hover:underline mt-1 ml-6">Edit Form Definition</button>}
                            </NexFormGroup>

                            <div className="h-px bg-slate-200"></div>

                            <NexFormGroup label="Role Assignment">
                                <select className="prop-input" value={step.role || ''} onChange={e => updateField('role', e.target.value)}>
                                    <option value="">Unassigned</option>
                                    {roles.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                                </select>
                            </NexFormGroup>
                            <NexFormGroup label="Candidate Groups">
                                <input className="prop-input" placeholder="group1, group2" value={step.data?.candidateGroups || ''} onChange={e => updateDataField('candidateGroups', e.target.value)} />
                            </NexFormGroup>
                        </div>
                    )}

                    {/* Gateway Specifics */}
                    {meta.category === 'Gateways' && (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--layout-gap)' }}>
                            <NexFormGroup label="Default Route ID">
                                <input className="prop-input font-mono" placeholder="Flow ID" value={step.data?.defaultFlow || ''} onChange={e => updateDataField('defaultFlow', e.target.value)} />
                            </NexFormGroup>
                            {step.type === 'exclusive-gateway' && (
                                <NexFormGroup label="Condition Expression (CEL)">
                                    <textarea className="prop-input h-24 font-mono text-xs" placeholder="amount > 1000 && approved == true" value={step.data?.condition || ''} onChange={e => updateDataField('condition', e.target.value)} />
                                </NexFormGroup>
                            )}
                        </div>
                    )}

                    {/* DYNAMIC SCHEMA RENDERING FOR ALL OTHER TYPES */}
                    {schema.map(renderDynamicField)}

                    {schema.length === 0 && step.type !== 'user-task' && meta.category !== 'Gateways' && (
                        <div className="text-center text-slate-400 italic text-xs">
                            No configuration required for this component.
                        </div>
                    )}
                </div>
            )}

            {/* TAB: DATA WIRING (Visual Mapper) */}
            {activeTab === 'data' && (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--layout-gap)' }}>
                    <div>
                        <div className="flex items-center justify-between mb-2">
                            <h4 className="text-[10px] font-bold text-slate-500 uppercase flex items-center gap-1"><ArrowRightLeft size={10}/> Input Transformation</h4>
                        </div>
                        <DataMapper 
                            mappings={step.inputs || []}
                            onChange={(m) => updateField('inputs', m)}
                            sourceSchema={PROCESS_VARS}
                            targetSchema={GET_TARGET_SCHEMA(step.type)}
                        />
                    </div>
                </div>
            )}

            {/* TAB: LOGIC (Rules & Triggers) */}
            {activeTab === 'logic' && (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--layout-gap)' }}>
                    <NexFormGroup label="Pre-Flight Rule" helpText="Execute business rule before step starts">
                            <select className="prop-input" value={step.businessRuleId || ''} onChange={e => updateField('businessRuleId', e.target.value)}>
                                <option value="">None</option>
                                {rules.map(r => <option key={r.id} value={r.id}>{r.name}</option>)}
                            </select>
                            {step.businessRuleId && (
                                <button onClick={() => navigateTo('rules', step.businessRuleId)} className="mt-1 text-[10px] text-blue-600 flex items-center gap-1 hover:underline">
                                    Edit Rule <ExternalLink size={10}/>
                                </button>
                            )}
                    </NexFormGroup>

                    <NexFormGroup label="On Entry Script">
                        <div className="relative">
                            <textarea className="prop-input h-20 font-mono text-[10px]" placeholder="console.log('Entering step');" value={step.onEntryAction || ''} onChange={e => updateField('onEntryAction', e.target.value)} />
                            {step.onEntryAction && <Sparkles size={12} className="absolute right-2 bottom-2 text-amber-500 animate-pulse"/>}
                        </div>
                    </NexFormGroup>

                    <NexFormGroup label="On Exit Script">
                        <textarea className="prop-input h-20 font-mono text-[10px]" placeholder="execution.setVariable('status', 'done');" value={step.onExitAction || ''} onChange={e => updateField('onExitAction', e.target.value)} />
                    </NexFormGroup>
                </div>
            )}

            {/* TAB: POLICY (Retry, Timeout, Escalation) */}
            {activeTab === 'policy' && (
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--layout-gap)' }}>
                    {/* Retry Section */}
                    <div className="space-y-3">
                        <div className="flex items-center justify-between">
                            <h4 className="text-xs font-bold text-slate-700 flex items-center gap-2"><RefreshCw size={12}/> Retry Policy</h4>
                            <label className="relative inline-flex items-center cursor-pointer">
                                <input type="checkbox" className="sr-only peer" checked={step.retryPolicy?.enabled || false} onChange={e => updateRetry('enabled', e.target.checked)} />
                                <div className="w-8 h-4 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-3 after:w-3 after:transition-all peer-checked:bg-blue-600"></div>
                            </label>
                        </div>

                        {step.retryPolicy?.enabled && (
                            <div className="p-3 bg-white border border-slate-200 rounded-sm space-y-3 animate-slide-up">
                                <NexFormGroup label="Strategy">
                                    <select className="prop-input" value={step.retryPolicy?.strategy || 'fixed'} onChange={e => updateRetry('strategy', e.target.value)}>
                                        <option value="fixed">Fixed Delay</option>
                                        <option value="exponential">Exponential Backoff</option>
                                        <option value="linear">Linear Backoff</option>
                                    </select>
                                </NexFormGroup>
                                <div className="grid grid-cols-2 gap-2">
                                    <NexFormGroup label="Max Attempts">
                                        <input type="number" className="prop-input" value={step.retryPolicy?.maxAttempts || 3} onChange={e => updateRetry('maxAttempts', parseInt(e.target.value))} />
                                    </NexFormGroup>
                                    <NexFormGroup label="Delay (ms)">
                                        <input type="number" className="prop-input" value={step.retryPolicy?.delayMs || 1000} onChange={e => updateRetry('delayMs', parseInt(e.target.value))} />
                                    </NexFormGroup>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="h-px bg-slate-200"></div>

                    {/* Escalation Section */}
                    <div className="space-y-3">
                        <div className="flex items-center justify-between">
                            <h4 className="text-xs font-bold text-slate-700 flex items-center gap-2"><Clock size={12}/> SLA & Escalation</h4>
                            <label className="relative inline-flex items-center cursor-pointer">
                                <input type="checkbox" className="sr-only peer" checked={step.escalation?.enabled || false} onChange={e => updateEscalation('enabled', e.target.checked)} />
                                <div className="w-8 h-4 bg-slate-200 peer-focus:outline-none rounded-full peer peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-3 after:w-3 after:transition-all peer-checked:bg-rose-500"></div>
                            </label>
                        </div>

                        {step.escalation?.enabled && (
                            <div className="p-3 bg-rose-50 border border-rose-100 rounded-sm space-y-3 animate-slide-up">
                                <NexFormGroup label="Trigger After (Days Overdue)">
                                    <input type="number" className="prop-input" value={step.escalation.daysAfterDue} onChange={e => updateEscalation('daysAfterDue', parseInt(e.target.value))} />
                                </NexFormGroup>
                                <NexFormGroup label="Escalation Action">
                                    <select className="prop-input" value={step.escalation.action} onChange={e => updateEscalation('action', e.target.value)}>
                                        <option value="notify_manager">Notify Manager</option>
                                        <option value="reassign">Auto-Reassign</option>
                                        <option value="auto_complete">Force Complete</option>
                                        <option value="trigger_bot">Trigger Remediation Bot</option>
                                    </select>
                                </NexFormGroup>
                                {step.escalation.action === 'reassign' && (
                                    <NexFormGroup label="Target Role ID">
                                        <input className="prop-input" value={step.escalation.targetId || ''} onChange={e => updateEscalation('targetId', e.target.value)} placeholder="e.g. manager" />
                                    </NexFormGroup>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            )}

            </div>

            {/* Footer Actions */}
            <div className="border-t border-slate-200 bg-slate-50 flex justify-between items-center" style={{ padding: 'var(--space-base)' }}>
            <button onClick={() => onDelete(step.id)} className="text-rose-600 hover:bg-rose-50 p-2 rounded-sm transition-colors" title="Delete Step">
                <Trash2 size={16}/>
            </button>
            <div className="text-[9px] text-slate-400 font-mono">ID: {step.id}</div>
            </div>
            </>
        )}
      </aside>
    );
};

