import React, { useState, useEffect, useMemo } from 'react';
import { FormDefinition, FormField, FormVisibilityRule } from '../../types';
import { NexFormGroup, NexButton } from './NexUI';
import { Check, X, PenTool, Info, Star, Plus, Minus, Lock, Upload, Calendar, Clock, ArrowRight, ArrowLeft } from 'lucide-react';

interface FormRendererProps {
  form: FormDefinition;
  data: Record<string, any>;
  onChange: (key: string, value: any) => void;
  readOnly?: boolean;
  errors?: Record<string, string>;
}

// Utility to validate form logic
export const validateForm = (form: FormDefinition, data: Record<string, any>): Record<string, string> => {
    const errors: Record<string, string> = {};

    const isVisible = (field: FormField) => {
        if (!field.visibility) return true;
        const { targetFieldKey, operator, value } = field.visibility;
        const targetValue = data[targetFieldKey];

        switch (operator) {
            case 'eq': return String(targetValue) === String(value);
            case 'neq': return String(targetValue) !== String(value);
            case 'contains': return String(targetValue).includes(String(value));
            case 'truthy': return !!targetValue;
            case 'falsy': return !targetValue;
            default: return true;
        }
    };

    form.fields.forEach(field => {
        if (!isVisible(field)) return;
        if (field.behavior?.readOnly || field.behavior?.disabled) return;

        const val = data[field.key];
        const isEmpty = val === undefined || val === null || val === '';

        if (field.required && isEmpty) {
            errors[field.key] = 'This field is required.';
        }

        if (!isEmpty && field.validation) {
            const { min, max, pattern, message } = field.validation;

            if (field.type === 'number' || field.type === 'slider' || field.type === 'rating') {
                const num = Number(val);
                if (min !== undefined && num < min) errors[field.key] = message || `Minimum value is ${min}`;
                if (max !== undefined && num > max) errors[field.key] = message || `Maximum value is ${max}`;
            }
            if (field.type === 'text' || field.type === 'textarea' || field.type === 'password') {
                if (min !== undefined && val.length < min) errors[field.key] = message || `Minimum length is ${min}`;
                if (max !== undefined && val.length > max) errors[field.key] = message || `Maximum length is ${max}`;
            }
            if (pattern) {
                const regex = new RegExp(pattern);
                if (!regex.test(String(val))) errors[field.key] = message || 'Invalid format.';
            }
        }
    });

    return errors;
};

// --- Extracted Components to avoid re-definition on render ---

const FieldWrapper: React.FC<{ field: FormField; children: React.ReactNode }> = ({ field, children }) => (
    <div className="relative w-full">
        {field.appearance?.prefix && <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-bold">{field.appearance.prefix}</span>}
        {children}
        {field.appearance?.suffix && <span className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-bold">{field.appearance.suffix}</span>}
    </div>
);

const SignatureField = ({ value, onChange, readOnly }: { value: string, onChange: (v: string) => void, readOnly?: boolean }) => {
    const isSigned = !!value;

    const handleSign = () => {
        if(readOnly) return;
        const hash = `SIGNED_${new Date().toISOString()}_${Math.random().toString(36).substr(2, 9)}`;
        onChange(hash);
    };

    const handleClear = () => {
        if(readOnly) return;
        onChange('');
    };

    return (
        <div className={`border rounded-sm p-4 flex items-center justify-between transition-colors w-full ${isSigned ? 'bg-emerald-50 border-emerald-200' : 'bg-white border-slate-300'}`}>
            <div className="flex items-center gap-3">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center ${isSigned ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>
                    {isSigned ? <Check size={20}/> : <PenTool size={20}/>}
                </div>
                <div>
                    <p className={`text-xs font-bold ${isSigned ? 'text-emerald-700' : 'text-slate-600'}`}>
                        {isSigned ? 'Digitally Signed' : 'Signature Required'}
                    </p>
                    {isSigned && <p className="text-[9px] font-mono text-emerald-600 mt-0.5">{value}</p>}
                </div>
            </div>
            {!readOnly && (
                <button 
                    onClick={isSigned ? handleClear : handleSign}
                    className={`px-3 py-1.5 text-xs font-bold rounded-sm transition-all ${isSigned ? 'text-rose-600 hover:bg-rose-50' : 'bg-blue-600 text-white hover:bg-blue-700'}`}
                >
                    {isSigned ? 'Clear' : 'Sign Now'}
                </button>
            )}
        </div>
    );
};

const FieldInput: React.FC<{ field: FormField; value: any; onChange: (k: string, v: any) => void; readOnly?: boolean }> = ({ field, value, onChange, readOnly }) => {
  const commonProps = {
    className: `prop-input w-full ${readOnly ? 'bg-slate-100 text-slate-500 cursor-not-allowed border-dashed' : ''} ${field.appearance?.prefix ? 'pl-8' : ''} ${field.appearance?.suffix ? 'pr-12' : ''}`,
    disabled: readOnly,
    value: value,
    onChange: (e: any) => onChange(field.key, e.target.value),
    placeholder: field.placeholder,
    readOnly: readOnly
  };

  switch (field.type) {
    case 'text':
    case 'email':
    case 'number':
    case 'password':
      return <FieldWrapper field={field}><input type={field.type === 'number' ? 'number' : field.type === 'password' ? 'password' : 'text'} {...commonProps} /></FieldWrapper>;

    case 'textarea':
      return <FieldWrapper field={field}><textarea {...commonProps} className={`${commonProps.className} h-24 resize-y py-2`} /></FieldWrapper>;

    case 'date':
      return <FieldWrapper field={field}><input type="date" {...commonProps} /></FieldWrapper>;

    case 'time':
      return <FieldWrapper field={field}><input type="time" {...commonProps} /></FieldWrapper>;

    case 'select':
      return (
        <FieldWrapper field={field}>
            <select {...commonProps}>
            <option value="">Select...</option>
            {field.options?.map(opt => (
                <option key={opt} value={opt}>{opt}</option>
            ))}
            </select>
        </FieldWrapper>
      );

    case 'checkbox':
      return (
        <div className="flex items-center gap-2 p-2 border border-transparent hover:bg-slate-50 rounded-sm -ml-2 transition-colors">
          <input 
            type="checkbox" 
            checked={!!value} 
            disabled={readOnly}
            onChange={(e) => onChange(field.key, e.target.checked)}
            className="w-4 h-4 text-blue-600 rounded-sm border-slate-300 focus:ring-blue-500 cursor-pointer"
          />
          <span className="text-sm text-slate-700 font-medium cursor-pointer" onClick={() => !readOnly && onChange(field.key, !value)}>{field.placeholder || 'Yes'}</span>
        </div>
      );

    case 'file':
      return (
        <div className="border border-dashed border-slate-300 rounded-sm p-4 text-center bg-slate-50 hover:bg-slate-100 transition-colors cursor-pointer w-full relative">
           <Upload size={20} className="mx-auto text-slate-400 mb-2"/>
           <span className="text-sm font-medium text-slate-600 block">Click to upload</span>
           <p className="text-[10px] text-slate-400 mt-1">{field.validation?.accept || 'All files'} (Max {field.validation?.maxSize ? field.validation.maxSize / 1024 / 1024 + 'MB' : 'Unlimited'})</p>
           {/* Visual only for demo */}
           <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" disabled={readOnly} />
        </div>
      );

    case 'signature':
        return <SignatureField value={value} onChange={(v) => onChange(field.key, v)} readOnly={readOnly} />;

    case 'rating':
        return (
            <div className="flex gap-1">
                {[1,2,3,4,5].map(v => (
                    <button type="button" key={v} onClick={() => !readOnly && onChange(field.key, v)} className={`transition-all hover:scale-110 ${value >= v ? 'text-amber-400' : 'text-slate-200'}`}>
                        <Star fill="currentColor" size={24} />
                    </button>
                ))}
            </div>
        );

    case 'slider':
        return (
            <div className="flex items-center gap-4">
                <input 
                    type="range" 
                    min={field.validation?.min || 0} 
                    max={field.validation?.max || 100} 
                    value={value || 0} 
                    onChange={e => onChange(field.key, Number(e.target.value))}
                    disabled={readOnly}
                    className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600" 
                />
                <span className="text-sm font-mono font-bold text-slate-700 w-8 text-right">{value || 0}</span>
            </div>
        );

    case 'color':
        return (
            <div className="flex items-center gap-2">
                <input type="color" value={value || '#000000'} onChange={e => onChange(field.key, e.target.value)} disabled={readOnly} className="h-9 w-16 p-0 border-0 rounded-sm cursor-pointer"/>
                <input type="text" value={value || ''} onChange={e => onChange(field.key, e.target.value)} className="prop-input flex-1" placeholder="#RRGGBB" disabled={readOnly}/>
            </div>
        );

    case 'tags':
        return (
            <div className="space-y-2">
                <div className="flex flex-wrap gap-2 mb-2">
                    {Array.isArray(value) && value.map((tag: string) => (
                        <span key={tag} className="bg-blue-50 text-blue-700 border border-blue-200 px-2 py-1 rounded-sm text-xs font-bold flex items-center gap-1">
                            {tag}
                            {!readOnly && <button type="button" onClick={() => onChange(field.key, value.filter((t: string) => t !== tag))}><X size={12}/></button>}
                        </span>
                    ))}
                </div>
                {!readOnly && (
                    <select 
                        className="prop-input" 
                        onChange={e => { 
                            const val = e.target.value; 
                            if(val && !value?.includes(val)) onChange(field.key, [...(value||[]), val]); 
                            e.target.value = '';
                        }}
                    >
                        <option value="">Add Tag...</option>
                        {field.options?.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                    </select>
                )}
            </div>
        );

    default:
      return <input type="text" {...commonProps} />;
  }
};

export const FormRenderer: React.FC<FormRendererProps> = ({ form, data, onChange, readOnly, errors = {} }) => {
  const [currentStep, setCurrentStep] = useState(0);

  // Group fields into steps based on Dividers
  const steps = useMemo(() => {
      const grouped: FormField[][] = [];
      let currentGroup: FormField[] = [];

      form.fields.forEach(field => {
          if (field.type === 'divider' && form.layoutMode === 'wizard') {
              if (currentGroup.length > 0) grouped.push(currentGroup);
              currentGroup = []; // Divider itself is consumed as a break
          } else {
              currentGroup.push(field);
          }
      });
      if (currentGroup.length > 0) grouped.push(currentGroup);

      // If single page mode or no dividers, just one group
      if (form.layoutMode !== 'wizard' || grouped.length === 0) return [form.fields];

      return grouped;
  }, [form.fields, form.layoutMode]);

  // Check visibility for all fields
  const isFieldVisible = (field: FormField): boolean => {
      if (!field.visibility) return true;
      const { targetFieldKey, operator, value } = field.visibility;
      const targetValue = data[targetFieldKey];

      switch (operator) {
          case 'eq': return String(targetValue) === String(value);
          case 'neq': return String(targetValue) !== String(value);
          case 'contains': return String(targetValue || '').includes(String(value || ''));
          case 'truthy': return !!targetValue;
          case 'falsy': return !targetValue;
          default: return true;
      }
  };

  // Perform Calculations (Basic implementation)
  useEffect(() => {
      form.fields.forEach(field => {
          if (field.behavior?.calculation) {
              // Very simple parser: {{var}} replacement then eval (dangerous in prod, good for demo)
              let calc = field.behavior.calculation;
              let hasVar = false;
              for(const key in data) {
                  if (calc.includes(`{{${key}}}`)) {
                      calc = calc.replace(new RegExp(`{{${key}}}`, 'g'), String(Number(data[key]) || 0));
                      hasVar = true;
                  }
              }
              if (hasVar) {
                  try {
                      // eslint-disable-next-line no-eval
                      const result = eval(calc); 
                      if (data[field.key] !== result) onChange(field.key, result);
                  } catch(e) {}
              }
          }
      });
  }, [data, form.fields]);

  const visibleFields = steps[currentStep] || [];

  return (
    <div className="flex flex-col h-full">
      {/* Wizard Progress Header */}
      {form.layoutMode === 'wizard' && steps.length > 1 && (
          <div className="flex items-center justify-between mb-6 px-2">
              {steps.map((_, idx) => (
                  <div key={idx} className="flex items-center flex-1 last:flex-none">
                      <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold transition-all ${idx <= currentStep ? 'bg-blue-600 text-white' : 'bg-slate-200 text-slate-500'}`}>
                          {idx + 1}
                      </div>
                      {idx < steps.length - 1 && (
                          <div className={`flex-1 h-1 mx-2 rounded-full ${idx < currentStep ? 'bg-blue-600' : 'bg-slate-200'}`}></div>
                      )}
                  </div>
              ))}
          </div>
      )}

      <div className="flex flex-wrap -mx-2 flex-1 content-start">
        {visibleFields.map(field => {
            if (!isFieldVisible(field)) return null;

            const width = field.layout?.width || '100%';
            const isDisabled = readOnly || field.behavior?.disabled || field.behavior?.readOnly;

            if (field.type === 'divider') {
                return (
                    <div key={field.id} className="w-full px-2 my-4">
                        <div className="h-px bg-slate-200 flex items-center justify-center">
                            <span className="bg-white px-2 text-xs font-bold text-slate-400 uppercase tracking-wider">{field.label}</span>
                        </div>
                    </div>
                );
            }

            if (field.type === 'rich-text') {
                return (
                    <div key={field.id} className="w-full px-2 mb-4">
                        <div className="p-3 bg-blue-50 border border-blue-100 rounded-sm text-sm text-blue-900" dangerouslySetInnerHTML={{__html: field.defaultValue || field.helpText || ''}} />
                    </div>
                )
            }

            return (
                <div key={field.id} className="px-2 mb-4" style={{ width }}>
                    <NexFormGroup 
                        label={field.label} 
                        helpText={field.required ? undefined : '(Optional)'}
                    >
                        <FieldInput field={field} value={data[field.key] || ''} onChange={onChange} readOnly={isDisabled} />
                    </NexFormGroup>

                    {field.helpText && (
                        <div className="mt-1 text-xs text-slate-500 flex items-start gap-1.5">
                            <Info size={12} className="shrink-0 mt-0.5 text-slate-400"/>
                            {field.helpText}
                        </div>
                    )}

                    {errors[field.key] && (
                        <div className="text-xs text-rose-600 font-bold mt-1 flex items-center gap-1 animate-pulse">
                            <X size={12}/> {errors[field.key]}
                        </div>
                    )}
                </div>
            );
        })}
      </div>

      {/* Wizard Footer */}
      {form.layoutMode === 'wizard' && steps.length > 1 && (
          <div className="flex justify-between pt-4 border-t border-slate-200 mt-4">
              <NexButton 
                variant="secondary" 
                onClick={() => setCurrentStep(Math.max(0, currentStep - 1))} 
                disabled={currentStep === 0} 
                icon={ArrowLeft}
              >
                  Back
              </NexButton>
              <NexButton 
                variant="primary" 
                onClick={() => setCurrentStep(Math.min(steps.length - 1, currentStep + 1))} 
                disabled={currentStep === steps.length - 1} 
                icon={ArrowRight}
              >
                  Next Step
              </NexButton>
          </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { 
  CheckCircle, AlertTriangle, 
  X, Activity, Send, Clock, PlayCircle, Rewind, FastForward, Pause, Play, History
} from 'lucide-react';
import { NexButton } from './shared/NexUI';

interface Props {
  instanceId: string;
  onClose: () => void;
}

export const ProcessInstanceViewer: React.FC<Props> = ({ instanceId, onClose }) => {
  const { instances, processes, addInstanceComment } = useBPM();

  const instance = instances.find(i => i.id === instanceId);
  const process = processes.find(p => p.id === instance?.definitionId);

  const [viewport, setViewport] = useState({ x: 0, y: 0, zoom: 1 });
  const [rightPanelTab, setRightPanelTab] = useState<'info' | 'variables' | 'comments'>('info');
  const [showAdminPanel, setShowAdminPanel] = useState(true);
  const [variableJson, setVariableJson] = useState('');
  const [newComment, setNewComment] = useState('');
  const [showMetrics, setShowMetrics] = useState(false);

  // Time Travel State
  const [playbackIndex, setPlaybackIndex] = useState<number>(-1); // -1 means live/latest
  const [isPlaying, setIsPlaying] = useState(false);

  const canvasRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);
  const dragStart = useRef({ x: 0, y: 0 });

  useEffect(() => {
    if (instance) {
        setVariableJson(JSON.stringify(instance.variables, null, 2));
        // Reset playback when instance loads
        setPlaybackIndex(instance.history.length - 1);
    }

    if (process && instance && instance.activeStepIds.length > 0 && canvasRef.current) {
      const activeStep = process.steps.find(s => s.id === instance.activeStepIds[0]);
      if (activeStep?.position) {
        setViewport({
          x: (canvasRef.current.clientWidth / 2) - activeStep.position.x - 90,
          y: (canvasRef.current.clientHeight / 2) - activeStep.position.y - 40,
          zoom: 1
        });
      }
    }
  }, [instanceId, process]);

  // Playback Loop
  useEffect(() => {
      let interval: any;
      if (isPlaying && instance) {
          interval = setInterval(() => {
              setPlaybackIndex(prev => {
                  if (prev >= instance.history.length - 1) {
                      setIsPlaying(false);
                      return prev;
                  }
                  return prev + 1;
              });
          }, 1000);
      }
      return () => clearInterval(interval);
  }, [isPlaying, instance]);

  // Derived State for Time Travel
  const currentHistoryItem = instance && playbackIndex >= 0 && playbackIndex < instance.history.length 
      ? instance.history[playbackIndex] 
      : null;

  // Calculate executed path links UP TO the playback index
  const executedLinks = useMemo(() => {
      if (!instance || !process) return [];

      const sortedHistory = [...instance.history].sort((a,b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());

      // Filter history based on playback
      const visibleHistory = playbackIndex === -1 ? sortedHistory : sortedHistory.slice(0, playbackIndex + 1);

      const takenPaths: Set<string> = new Set();
      const stepIdByName = new Map(process.steps.map(s => [s.name, s.id]));

      const startNode = process.steps.find(s => s.type === 'start');
      let previousStepId = startNode?.id;

      visibleHistory.forEach(h => {
          const currentStepId = stepIdByName.get(h.stepName);
          if (previousStepId && currentStepId) {
              const link = process.links?.find(l => l.sourceId === previousStepId && l.targetId === currentStepId);
              if (link) takenPaths.add(link.id);
              previousStepId = currentStepId;
          }
      });

      return Array.from(takenPaths);
  }, [instance, process, playbackIndex]);

  // Determine Active Steps based on Playback
  // If playing back, the "active" step is the one in the current history item
  const displayActiveStepIds = useMemo(() => {
      if (!instance || !process) return [];
      if (playbackIndex === -1 || playbackIndex === instance.history.length - 1) return instance.activeStepIds;

      // Find the step ID corresponding to the current history item
      if (currentHistoryItem) {
          const step = process.steps.find(s => s.name === currentHistoryItem.stepName);
          return step ? [step.id] : [];
      }
      return [];
  }, [instance, process, playbackIndex, currentHistoryItem]);

  const handlePointerDown = (e: React.PointerEvent) => {
    isDragging.current = true;
    dragStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!isDragging.current) return;
    setViewport(prev => ({ ...prev, x: prev.x + (e.clientX - dragStart.current.x), y: prev.y + (e.clientY - dragStart.current.y) }));
    dragStart.current = { x: e.clientX, y: e.clientY };
  };

  const handlePointerUp = () => { isDragging.current = false; };

  // Health Logic
  const isHealthy = instance && (instance.status === 'Active' || instance.status === 'Completed');

  const handleAddComment = () => {
      if(!newComment.trim() || !instance) return;
      if (addInstanceComment) {
          addInstanceComment(instance.id, newComment);
      }
      setNewComment('');
  };

  const adminPanelWidth = rightPanelTab === 'variables' ? 'w-[500px]' : 'w-[320px]';

  // --- SAFE RENDER ---
  // Hooks have been called. Now we can conditionally return.
  if (!instance || !process) return null;

  return (
    <div className="fixed inset-0 bg-slate-100 z-[100] flex flex-col animate-fade-in overflow-hidden">
      <div className="h-12 bg-white border-b border-slate-300 flex items-center justify-between px-4 z-50 shadow-sm">
        <div className="flex items-center gap-3">
           <button onClick={onClose} className="p-1.5 hover:bg-slate-100 rounded-sm text-slate-500"><X size={18}/></button>
           <div className="h-5 w-px bg-slate-200"></div>
           <div className="flex items-center gap-3">
             <h2 className="font-bold text-slate-800 text-sm tracking-tight">{process.name}</h2>
             <span className={`px-2 py-0.5 rounded-sm text-[10px] font-bold uppercase border ${instance.status === 'Active' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-rose-50 text-rose-700 border-rose-200'}`}>{instance.status}</span>
             <span className="text-[10px] text-slate-400 font-mono">{instance.id}</span>
           </div>
        </div>
        <div className="flex items-center gap-2">
            <label className="flex items-center gap-2 text-xs font-bold text-slate-600 mr-4 cursor-pointer select-none">
                <input type="checkbox" checked={showMetrics} onChange={e => setShowMetrics(e.target.checked)} className="rounded-sm text-blue-600"/>
                Show Metrics
            </label>
            <button onClick={() => setShowAdminPanel(!showAdminPanel)} className={`p-1.5 rounded-sm ${showAdminPanel ? 'bg-slate-200 text-slate-900' : 'text-slate-500 hover:bg-slate-100'}`}><Activity size={18}/></button>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden relative">
        <div 
          ref={canvasRef}
          className="flex-1 relative bg-[#f0f2f5] touch-none designer-grid"
          onPointerDown={handlePointerDown}
          onPointerMove={handlePointerMove}
          onPointerUp={handlePointerUp}
        >
          <div style={{ transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.zoom})`, transformOrigin: '0 0' }}>
             <svg className="overflow-visible absolute top-0 left-0 pointer-events-none">
                {process.steps.flatMap(step => (step.nextStepIds || []).map(targetId => {
                  const t = process.steps.find(s => s.id === targetId);
                  const link = process.links?.find(l => l.sourceId === step.id && l.targetId === t?.id);

                  if (!t || !step.position || !t.position) return null;
                  const x1=step.position.x+200; const y1=step.position.y+40;
                  const x2=t.position.x; const y2=t.position.y+40;

                  const isTraversed = link && executedLinks.includes(link.id);

                  return (
                      <g key={`${step.id}-${targetId}`}>
                          {/* Base Line */}
                          <path d={`M ${x1} ${y1} C ${x1+50} ${y1}, ${x2-50} ${y2}, ${x2} ${y2}`} stroke={isTraversed ? "#10b981" : "#cbd5e1"} strokeWidth={isTraversed ? 4 : 2} fill="none" className="transition-all duration-1000 ease-out"/>
                          {/* Animated Dash for Active Paths */}
                          {isTraversed && (
                              <path d={`M ${x1} ${y1} C ${x1+50} ${y1}, ${x2-50} ${y2}, ${x2} ${y2}`} stroke="#ffffff" strokeWidth="2" strokeDasharray="10,10" fill="none" className="animate-[dash_1s_linear_infinite] opacity-30"/>
                          )}
                      </g>
                  );
                }))}
             </svg>

             {process.steps.map(step => {
               const isActive = displayActiveStepIds.includes(step.id);
               // Visited if in history UP TO playback index
               const isVisited = instance.history.slice(0, playbackIndex + 1).some(h => h.stepName === step.name);

               // Mock Metrics
               const avgDuration = step.metrics?.avgDuration || (Math.floor(Math.random() * 120) + 10);
               const errorRate = step.metrics?.errorRate || Math.floor(Math.random() * 5);

               return (
               <div key={step.id} className={`absolute w-[200px] h-[80px] rounded-sm border flex flex-col p-3 transition-all ${isActive ? 'bg-white border-emerald-500 ring-4 ring-emerald-500/20 z-10 shadow-lg scale-105' : (isVisited ? 'bg-white border-emerald-200' : 'bg-white border-slate-300 opacity-60')}`} style={{ left: step.position?.x, top: step.position?.y }}>
                  <div className="text-[9px] font-bold uppercase text-slate-400 mb-1 flex justify-between">
                      {step.type}
                      {isActive && <span className="text-emerald-600 animate-pulse flex items-center gap-1"><PlayCircle size={10}/> LIVE</span>}
                  </div>
                  <div className="text-xs font-bold truncate text-slate-800">{step.name}</div>

                  {showMetrics && (
                      <div className="mt-auto pt-2 border-t border-slate-100 flex justify-between text-[9px] font-mono text-slate-500">
                          <span className="flex items-center gap-1" title="Avg Duration"><Clock size={10}/> {avgDuration}m</span>
                          <span className={`flex items-center gap-1 ${errorRate > 2 ? 'text-rose-600' : 'text-slate-500'}`} title="Error Rate"><AlertTriangle size={10}/> {errorRate}%</span>
                      </div>
                  )}
               </div>
             )})}
          </div>
        </div>

        {/* Time Travel Controls (Bottom Overlay) */}
        <div className="absolute bottom-6 left-6 right-6 lg:right-96 bg-white/90 backdrop-blur border border-slate-200 rounded-sm p-4 shadow-xl z-40 flex flex-col gap-2 animate-slide-up">
            <div className="flex items-center justify-between text-xs font-bold text-slate-600 uppercase tracking-wider">
                <span className="flex items-center gap-2"><History size={14}/> Time Travel Debugger</span>
                <span>{currentHistoryItem ? new Date(currentHistoryItem.timestamp).toLocaleString() : 'Live'}</span>
            </div>
            <div className="flex items-center gap-4">
                <button onClick={() => setIsPlaying(!isPlaying)} className={`p-2 rounded-full text-white transition-all ${isPlaying ? 'bg-amber-500 hover:bg-amber-600' : 'bg-blue-600 hover:bg-blue-700'}`}>
                    {isPlaying ? <Pause size={16}/> : <Play size={16}/>}
                </button>
                <div className="flex-1 relative h-8 flex items-center">
                    <div className="absolute left-0 right-0 h-1.5 bg-slate-200 rounded-full"></div>
                    <div className="absolute left-0 h-1.5 bg-blue-500 rounded-full transition-all duration-300" style={{ width: `${((playbackIndex + 1) / instance.history.length) * 100}%` }}></div>
                    <input 
                        type="range" 
                        min={-1} 
                        max={instance.history.length - 1} 
                        value={playbackIndex} 
                        onChange={(e) => { setPlaybackIndex(parseInt(e.target.value)); setIsPlaying(false); }}
                        className="absolute inset-0 w-full opacity-0 cursor-pointer"
                    />
                    {instance.history.map((h, i) => (
                        <div key={i} className="absolute w-2 h-2 rounded-full bg-white border-2 border-slate-300 top-1/2 -translate-y-1/2 pointer-events-none" style={{ left: `${((i + 1) / instance.history.length) * 100}%`, transform: 'translateX(-50%) translateY(-50%)' }} title={h.stepName}></div>
                    ))}
                </div>
                <button onClick={() => setPlaybackIndex(-1)} className="p-2 text-slate-500 hover:text-blue-600" title="Jump to Live"><FastForward size={16}/></button>
            </div>
            <div className="text-center text-[10px] text-slate-400 font-mono">
