export const ProcessDesigner: React.FC = () => {
  const { deployProcess, roles, addNotification, designerDraft, setDesignerDraft, nav, currentUser, processes } = useBPM();

  const [nodes, setNodes] = useNodesState([]);
  const [edges, setEdges] = useEdgesState([]);

  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
  const [contextMenu, setContextMenu] = useState<{ position: { x: number; y: number }, targetId: string | null } | null>(null);

  const [processMeta, setProcessMeta] = useState<Partial<ProcessDefinition>>({ 
      name: 'Strategic Workflow', 
      description: '', 
      version: 1, 
      complianceLevel: 'Standard',
      domainId: currentUser?.domainId || 'GLOBAL',
      lanes: []
  });

  const [leftOpen, setLeftOpen] = useState(true);
  const [rightOpen, setRightOpen] = useState(true);
  const [viewMode, setViewMode] = useState<'canvas' | 'hierarchy'>('canvas');
  const [aiPrompt, setAiPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [showHeatmap, setShowHeatmap] = useState(false);

  useEffect(() => {
      if (nav.selectedId && nav.view === 'designer') {
          const existing = processes.find(p => p.id === nav.selectedId);
          if (existing) {
              setProcessMeta({
                  id: existing.id,
                  name: existing.name,
                  description: existing.description,
                  version: existing.version,
                  complianceLevel: existing.complianceLevel,
                  domainId: existing.domainId,
                  lanes: existing.lanes || []
              });

              const dbNodes: Node[] = existing.steps.map(s => ({
                  id: s.id,
                  type: 'custom',
                  position: s.position || { x: 0, y: 0 },
                  data: { step: s }
              }));

              const dbEdges: Edge[] = (existing.links || []).map(l => ({
                  id: l.id,
                  source: l.sourceId,
                  target: l.targetId,
                  type: 'custom',
                  label: l.label
              }));

              setNodes(dbNodes);
              setEdges(dbEdges);
              return; 
          }
      }

      if (designerDraft && (!nav.selectedId || nav.selectedId === 'new')) {
          const draftNodes: Node[] = designerDraft.steps.map(s => ({
            id: s.id,
            type: 'custom',
            position: s.position || { x: 0, y: 0 },
            data: { step: s }
          }));
          const draftEdges: Edge[] = designerDraft.links.map(l => ({
            id: l.id,
            source: l.sourceId,
            target: l.targetId,
            type: 'custom',
            label: l.label
          }));
          setNodes(draftNodes);
          setEdges(draftEdges);
      }
  }, [nav.selectedId, processes, designerDraft, nav.view, setNodes, setEdges]); 

  const setDesignerDraftRef = useRef(setDesignerDraft);
  useEffect(() => {
      setDesignerDraftRef.current = setDesignerDraft;
  }, [setDesignerDraft]);

  useEffect(() => {
    const handler = setTimeout(() => {
        const steps: ProcessStep[] = nodes.map(n => ({
          ...n.data.step,
          position: n.position,
          id: n.id 
        }));

        const links: ProcessLink[] = edges.map(e => ({
          id: e.id,
          sourceId: e.source,
          targetId: e.target,
          label: e.label as string
        }));

        setDesignerDraftRef.current({ steps, links });
    }, 1000); 

    return () => clearTimeout(handler);
  }, [nodes, edges]);

  const isValidConnection = useCallback((connection: Connection) => {
      const sourceNode = nodes.find(n => n.id === connection.source);
      const targetNode = nodes.find(n => n.id === connection.target);

      if (!sourceNode || !targetNode) return false;
      if (sourceNode.data.step.type === 'end') return false;
      if (targetNode.data.step.type === 'start') return false;
      if (connection.source === connection.target) return false;

      return true;
  }, [nodes]);

  const onLayout = useCallback((direction: 'LR' | 'TB') => {
      const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(
        nodes,
        edges,
        direction
      );
      setNodes([...layoutedNodes]);
      setEdges([...layoutedEdges]);
  }, [nodes, edges, setNodes, setEdges]);

  const handleAutoFix = useCallback(() => {
      let fixesApplied = 0;
      let newNodes = [...nodes];
      let newEdges = [...edges];

      if (!newNodes.some(n => n.data.step.type === 'start')) {
          const startId = `node-start-${Date.now()}`;
          const startNode: Node = {
              id: startId,
              type: 'custom',
              position: { x: 50, y: 150 },
              data: { step: { id: startId, name: 'Start', type: 'start', description: 'Auto-added start' } }
          };
          newNodes = [startNode, ...newNodes];
          fixesApplied++;

          if (newNodes.length > 1) {
              const target = newNodes[1];
              newEdges.push({ id: `edge-fix-${Date.now()}`, source: startId, target: target.id, type: 'custom' });
          }
      }

      if (!newNodes.some(n => n.data.step.type === 'end')) {
          const sources = new Set(newEdges.map(e => e.source));
          const leafNodes = newNodes.filter(n => !sources.has(n.id) && n.data.step.type !== 'start');

          const endId = `node-end-${Date.now()}`;
          const endNode: Node = {
              id: endId,
              type: 'custom',
              position: { x: 800, y: 150 }, 
              data: { step: { id: endId, name: 'End', type: 'end', description: 'Auto-added end' } }
          };
          newNodes.push(endNode);
          fixesApplied++;

          leafNodes.forEach((leaf, idx) => {
              newEdges.push({ id: `edge-fix-end-${idx}-${Date.now()}`, source: leaf.id, target: endId, type: 'custom' });
          });
      }

      if (fixesApplied > 0) {
          const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(newNodes, newEdges, 'LR');
          setNodes(layoutedNodes);
          setEdges(layoutedEdges);
          addNotification('success', `Auto-fix applied: Added ${fixesApplied} missing elements and reorganized.`);
      } else {
          addNotification('info', 'Structure appears valid. Re-running layout.');
          onLayout('LR');
      }
  }, [nodes, edges, setNodes, setEdges, addNotification, onLayout]);

  const onDragOver = useCallback((event: React.DragEvent) => {
    event.preventDefault();
    event.dataTransfer.dropEffect = 'move';
  }, []);

  const addNode = useCallback((type: ProcessStepType, position?: { x: number, y: number }) => {
    const metadata = getStepTypeMetadata(type);
    const id = `node-${Date.now()}`;

    const newStep: ProcessStep = {
      id,
      name: metadata.defaultName,
      type,
      description: '',
      requiredSkills: metadata.defaultSkills || [],
      data: {}
    };

    const newNode: Node = {
      id,
      type: 'custom',
      position: position || { x: 250, y: 250 }, 
      data: { step: newStep }
    };

    setNodes((nds) => nds.concat(newNode));
    setSelectedNodeId(id);
    if (!rightOpen) setRightOpen(true);
  }, [setNodes, rightOpen]);

  const onDrop = useCallback(
    (event: React.DragEvent) => {
      event.preventDefault();
      const type = event.dataTransfer.getData('application/reactflow');
      if (!type) return;

      const position = {
        x: event.clientX - 280, 
        y: event.clientY - 80, 
      };

      addNode(type as ProcessStepType, position);
    },
    [addNode] 
  );

  const onConnect = useCallback((params: Connection) => setEdges((eds) => addEdge({ ...params, type: 'custom' }, eds)), [setEdges]);

  const updateSelectedStep = useCallback((updatedStep: ProcessStep) => {
    setNodes((nds) => nds.map((n) => {
      if (n.id === updatedStep.id) {
        return { ...n, data: { ...n.data, step: updatedStep } };
      }
      return n;
    }));
  }, [setNodes]);

  const deleteNode = useCallback((id: string) => {
    setNodes((nds) => nds.filter((n) => n.id !== id));
    setEdges((eds) => eds.filter((e) => e.source !== id && e.target !== id));
    setSelectedNodeId(null);
  }, [setNodes, setEdges]);

  const handleDeploy = async () => {
    const invalidNodes = nodes.filter(n => !validateStepConfiguration(n.data.step.type, n.data.step.data));
    if (invalidNodes.length > 0) {
        addNotification('error', `Deploy Failed: ${invalidNodes.length} steps have missing configuration. Check indicators.`);
        setSelectedNodeId(invalidNodes[0].id);
        setRightOpen(true);
        return;
    }

    const steps: ProcessStep[] = nodes.map(n => ({
        ...n.data.step,
        position: n.position,
        nextStepIds: edges.filter(e => e.source === n.id).map(e => e.target)
    }));

    const links: ProcessLink[] = edges.map(e => ({
        id: e.id,
        sourceId: e.source,
        targetId: e.target
    }));

    await deployProcess({ 
        ...processMeta,
        steps, 
        links, 
        isActive: true, 
        version: (processMeta.version || 1) + 1 
    });
    addNotification('success', `Process ${processMeta.name} deployed successfully.`);
  };

  const handleClear = () => {
    if(window.confirm('Clear current design?')) {
        setNodes([]);
        setEdges([]);
        setSelectedNodeId(null);
    }
  };

  const handleAiGenerate = async (e: React.KeyboardEvent) => {
    if (!aiPrompt.trim()) return;
    setIsGenerating(true);
    try {
      const generatedSteps = await generateProcessWorkflow(aiPrompt);
      if (generatedSteps && generatedSteps.length > 0) {
        const newNodes: Node[] = generatedSteps.map(s => ({
            id: s.id,
            type: 'custom',
            position: s.position || { x: 0, y: 0 },
            data: { step: s }
        }));

        const newEdges: Edge[] = [];
        for(let i=0; i < generatedSteps.length - 1; i++) {
            newEdges.push({ 
                id: `link-auto-${i}`, 
                source: generatedSteps[i].id, 
                target: generatedSteps[i+1].id,
                type: 'custom'
            });
        }

        const { nodes: layoutedNodes, edges: layoutedEdges } = getLayoutedElements(newNodes, newEdges, 'LR');

        setNodes(layoutedNodes);
        setEdges(layoutedEdges);
        addNotification('success', 'Model synthesized and auto-layout applied.');
        setAiPrompt('');
      }
    } catch (err) { addNotification('error', 'Generation failure.'); } finally { setIsGenerating(false); }
  };

  const handleSimulation = () => {
    if (nodes.length === 0) {
      addNotification('error', 'Canvas is empty. Add steps to simulate.');
      return;
    }
    navigateTo('simulation-report');
  };

  const onContextMenu = useCallback((event: React.MouseEvent, node?: Node) => {
    event.preventDefault();
    setContextMenu({
      position: { x: event.clientX, y: event.clientY },
      targetId: node ? node.id : null,
    });
  }, []);

  const handleMenuAction = (action: string, payload?: unknown) => {
    if (!contextMenu) return;
    const { targetId } = contextMenu;

    switch (action) {
      case 'delete':
        if (targetId) deleteNode(targetId);
        break;
      case 'duplicate':
        if (targetId) {
          const original = nodes.find(n => n.id === targetId);
          if (original) {
            const id = `node-${Date.now()}`;
            const newNode = {
              ...original,
              id,
              position: { x: original.position.x + 50, y: original.position.y + 50 },
              data: { step: { ...original.data.step, id, name: `${original.data.step.name} (Copy)` } },
              selected: true
            };
            setNodes(nds => nds.map(n => ({...n, selected: false})).concat(newNode));
            setSelectedNodeId(id);
          }
        }
        break;
      case 'add-node':
        addNode(payload as ProcessStepType, { x: 250, y: 250 });
        break;
      case 'clear-canvas':
        handleClear();
        break;
    }
    setContextMenu(null);
  };

  const selectedStep = useMemo(() => {
    const node = nodes.find(n => n.id === selectedNodeId);
    return node ? node.data.step : undefined;
  }, [selectedNodeId, nodes]);

  useEffect(() => {
      if (selectedNodeId && !rightOpen) {
          setRightOpen(true);
      }
  }, [selectedNodeId]);

  return (
      <div 
        className="flex flex-col bg-panel border border-default rounded-base shadow-sm overflow-hidden"
        style={{ 
          height: 'calc(100vh - 100px)',
          borderRadius: 'var(--radius-base)' 
        }}
      >
        <div 
          className="bg-subtle border-b border-default flex items-center justify-between shrink-0"
          style={{ 
            height: 'var(--header-height)', 
            paddingLeft: 'var(--layout-padding)', 
            paddingRight: 'var(--layout-padding)' 
          }}
        >
           <div className="flex items-center" style={{ gap: 'var(--space-base)' }}>
              <button 
                onClick={() => setLeftOpen(!leftOpen)} 
                className={`p-1 rounded-base hover:bg-white border border-transparent hover:border-subtle ${leftOpen ? 'text-blue-600' : 'text-secondary'}`}
                title="Toggle Library"
              >
                <LayoutPanelLeft size={16}/>
              </button>
              <div className="h-4 w-px bg-default"></div>
              <div className="flex flex-col justify-center">
                  <input 
                    className="bg-transparent text-sm font-bold text-primary w-48 outline-none" 
                    value={processMeta.name} 
                    onChange={e => setProcessMeta(p => ({ ...p, name: e.target.value }))} 
                  />
                  {processMeta.id && <span className="text-[9px] text-slate-400 font-mono leading-none">ID: {processMeta.id}</span>}
              </div>
           </div>

           <div className="flex items-center p-0.5 rounded-base border border-default bg-slate-200/50" style={{ gap: 'calc(var(--space-base) * 0.5)' }}>
              <button 
                onClick={() => setViewMode('canvas')}
                className={`flex items-center gap-2 px-3 py-1 rounded-sm text-xs font-medium transition-all ${viewMode === 'canvas' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                <Grid size={14}/> Canvas
              </button>
              <button 
                onClick={() => setViewMode('hierarchy')}
                className={`flex items-center gap-2 px-3 py-1 rounded-sm text-xs font-medium transition-all ${viewMode === 'hierarchy' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                <ListTree size={14}/> Hierarchy
              </button>
           </div>

           <div className="flex items-center" style={{ gap: 'var(--space-base)' }}>
              <input className="h-7 w-48 bg-panel border border-default rounded-base px-2 text-xs hidden lg:block" placeholder="Describe workflow for AI generation..." value={aiPrompt} onChange={e => setAiPrompt(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAiGenerate(e)} disabled={isGenerating}/>

              <button 
                className="p-1.5 text-amber-600 hover:bg-amber-50 rounded-base border border-transparent hover:border-amber-200 transition-all" 
                onClick={handleAutoFix} 
                title="Auto-Fix Structure"
              >
                <Wand2 size={16}/>
              </button>

              <button className="p-1 text-secondary hover:text-rose-600" onClick={handleClear} title="Clear Canvas"><Trash2 size={16}/></button>

              <div className="h-4 w-px bg-default mx-1"></div>

              <button 
                  onClick={() => setShowHeatmap(!showHeatmap)} 
                  className={`p-1 rounded-base transition-colors ${showHeatmap ? 'bg-rose-100 text-rose-600' : 'text-secondary hover:text-primary'}`} 
                  title="Toggle Heatmap"
              >
                  <Thermometer size={16}/>
              </button>

              <button onClick={handleSimulation} className="flex items-center gap-1 px-3 py-1 bg-indigo-600 text-white rounded-base text-xs hover:bg-indigo-700 shadow-sm"><Cpu size={14}/> Simulate</button>
              <button onClick={handleDeploy} className="flex items-center gap-1 px-3 py-1 bg-brand-slate text-white rounded-base text-xs hover:bg-slate-900 shadow-sm"><Save size={14}/> Save</button>

              <div className="h-4 w-px bg-default mx-1"></div>

              <button 
                onClick={() => setRightOpen(!rightOpen)} 
                className={`p-1 rounded-base hover:bg-white border border-transparent hover:border-subtle ${rightOpen ? 'text-blue-600' : 'text-secondary'}`}
                title="Toggle Properties"
              >
                <PanelRight size={16}/>
              </button>
           </div>
        </div>

        <div className="flex-1 flex overflow-hidden">
          <div className={`border-r border-default bg-subtle overflow-y-auto z-10 transition-all duration-300 ${leftOpen ? 'w-56' : 'w-0 border-none'}`}>
             <PaletteSidebar onAddNode={(type) => addNode(type)} />
          </div>

          <div className="flex-1 h-full relative" onContextMenu={onContextMenu}>
             {viewMode === 'canvas' ? (
                <DesignerFlow 
                    nodes={nodes} 
                    edges={edges}
                    onNodesChange={onNodesChange}
                    onEdgesChange={onEdgesChange}
                    onConnect={onConnect}
                    onNodeClick={(e, node) => { setSelectedNodeId(node.id); }}
                    onPaneClick={() => setSelectedNodeId(null)}
                    onContextMenu={onContextMenu}
                    onDrop={onDrop}
                    onDragOver={onDragOver}
                    onLayout={onLayout}
                    isValidConnection={isValidConnection}
                    lanes={processMeta.lanes}
                />
             ) : (
                <HierarchyView nodes={nodes} edges={edges} onSelectNode={setSelectedNodeId} selectedNodeId={selectedNodeId} />
             )}

             {/* Heatmap Overlay */}
             {showHeatmap && (
                 <div className="absolute inset-0 pointer-events-none z-10 bg-black/5">
                     <div className="absolute top-4 left-1/2 -translate-x-1/2 bg-rose-600 text-white px-3 py-1 rounded-full text-xs font-bold shadow-lg animate-pulse">
                         Live Traffic Heatmap (Simulated)
                     </div>
                 </div>
             )}

             <CanvasContextMenu 
                position={contextMenu ? contextMenu.position : null} 
                targetId={contextMenu ? contextMenu.targetId : null} 
                onClose={() => setContextMenu(null)}
                onAction={handleMenuAction}
             />
          </div>

          <div className={`${rightOpen ? 'w-[320px] md:w-[400px]' : 'w-0'} border-l border-default bg-white transition-all duration-300 z-20 shadow-xl overflow-hidden`}>
             {selectedStep ? (
                 <PropertiesPanel 
                    step={selectedStep} 
                    onUpdate={updateSelectedStep} 
                    onDelete={deleteNode} 
                    roles={roles}
                    onClose={() => setSelectedNodeId(null)}
                 />
             ) : (
                 <ProcessSettingsPanel 
                    meta={processMeta} 
                    onChange={setProcessMeta} 
                    onClose={() => setRightOpen(false)}
                    roles={roles}
                 />
             )}
          </div>
        </div>
      </div>
  );
};

import React, { useState } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { Play, FileText, Layers, Plus, Edit, MoreVertical, Copy, Trash2, PauseCircle, StopCircle, Search, History, BookOpen } from 'lucide-react';
import { NexBadge, NexModal } from './shared/NexUI';
import { ProcessDiffViewer } from './governance/ProcessDiffViewer';
import { ProcessDefinition } from '../types';
import { generateProcessDocumentation } from '../services/geminiService';

export const ProcessRepository: React.FC = () => {
  const { processes, instances, startProcess, openInstanceViewer, deployProcess, deleteProcess, toggleProcessState, suspendInstance, terminateInstance, navigateTo } = useBPM();
  const [activeTab, setActiveTab] = useState<'definitions' | 'instances'>('definitions');
  const [filterQuery, setFilterQuery] = useState('');
  const [showArchived, setShowArchived] = useState(false);

  // History Modal State
  const [selectedHistoryProc, setSelectedHistoryProc] = useState<ProcessDefinition | null>(null);
  const [historyModalOpen, setHistoryModalOpen] = useState(false);

  // Docs Modal State
  const [docContent, setDocContent] = useState('');
  const [docModalOpen, setDocModalOpen] = useState(false);
  const [, setGeneratingDocs] = useState(false);

  const handleStart = (id: string) => {
    startProcess(id, { summary: `Automated initiation via Registry` });
  };

  const handleDuplicate = async (proc: ProcessDefinition) => {
      const newProc: Partial<ProcessDefinition> = { ...proc, id: undefined, name: `${proc.name} (Copy)`, version: 1, history: [] };
      await deployProcess(newProc);
  };

  const handleViewHistory = (proc: ProcessDefinition) => {
      setSelectedHistoryProc(proc);
      setHistoryModalOpen(true);
  };

  const handleGenerateDocs = async (proc: ProcessDefinition) => {
      setGeneratingDocs(true);
      setDocModalOpen(true);
      setDocContent('<div class="p-8 text-center"><p>Generating documentation...</p></div>');
      try {
          const html = await generateProcessDocumentation(proc);
          setDocContent(html);
      } catch (e) {
          setDocContent('<p>Error generating documentation.</p>');
      } finally {
          setGeneratingDocs(false);
      }
  };

  const filteredProcesses = processes.filter(p => 
      (p.name.toLowerCase().includes(filterQuery.toLowerCase()) || p.description.toLowerCase().includes(filterQuery.toLowerCase())) &&
      (showArchived ? true : p.isActive)
  );

  const filteredInstances = instances.filter(i => 
      i.definitionName.toLowerCase().includes(filterQuery.toLowerCase()) || 
      i.id.includes(filterQuery)
  );

  return (
    <div 
      className="animate-fade-in pb-20 flex flex-col"
      style={{ gap: 'var(--section-gap)' }}
    >
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 border-b border-slate-300 pb-4">
        <div>
          <h2 className="text-xl font-bold text-slate-800 tracking-tight">Process Registry</h2>
          <p className="text-xs text-slate-500 font-medium">Authoritative source for deployed models and runtimes.</p>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-sm border border-slate-200">
           <button 
             onClick={() => setActiveTab('definitions')}
             className={`px-4 py-1.5 rounded-sm text-xs font-semibold transition-all ${activeTab === 'definitions' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
           >
             Definitions
           </button>
           <button 
             onClick={() => setActiveTab('instances')}
             className={`px-4 py-1.5 rounded-sm text-xs font-semibold transition-all ${activeTab === 'instances' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
           >
             Active Runtimes ({instances.filter(i => i.status === 'Active').length})
           </button>
        </div>
      </header>

      {/* Filter Bar */}
      <div className="flex gap-4 items-center">
          <div className="relative flex-1">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14}/>
              <input 
                className="w-full pl-9 pr-3 py-2 bg-white border border-slate-300 rounded-sm text-xs font-medium focus:ring-1 focus:ring-blue-600 outline-none" 
                placeholder={activeTab === 'definitions' ? "Search definitions..." : "Search instances..."}
                value={filterQuery}
                onChange={e => setFilterQuery(e.target.value)}
              />
          </div>
          {activeTab === 'definitions' && (
              <label className="flex items-center gap-2 text-xs text-slate-600 font-medium cursor-pointer select-none">
                  <input type="checkbox" checked={showArchived} onChange={e => setShowArchived(e.target.checked)} className="rounded-sm border-slate-300 text-blue-600 focus:ring-blue-500"/>
                  Show Archived
              </label>
          )}
      </div>

      {activeTab === 'definitions' ? (
        <div 
          className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3"
          style={{ gap: 'var(--layout-gap)' }}
        >
          <button onClick={() => navigateTo('designer')} className="group border border-dashed border-slate-300 rounded-sm p-6 flex flex-col items-center justify-center text-slate-400 hover:border-blue-500 hover:bg-blue-50 transition-all min-h-[200px]">
             <Plus size={24} className="mb-2 group-hover:text-blue-600"/>
             <span className="text-xs font-bold uppercase tracking-wider group-hover:text-blue-700">Deploy New Model</span>
          </button>

          {filteredProcesses.map(process => (
            <div 
              key={process.id} 
              className="bg-white rounded-sm border border-slate-300 shadow-sm flex flex-col hover:border-blue-400 transition-all group relative"
              style={{ padding: 'var(--card-padding)' }}
            >
              <div className="flex items-start justify-between mb-4">
                 <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-sm transition-colors ${process.isActive ? 'bg-slate-100 text-slate-600 group-hover:bg-blue-600 group-hover:text-white' : 'bg-slate-100 text-slate-400'}`}>
                        <Layers size={18} />
                    </div>
                    <div>
                        <h3 className={`text-sm font-bold ${process.isActive ? 'text-slate-800' : 'text-slate-500 line-through'}`}>{process.name}</h3>
                        <div className="flex items-center gap-2 mt-0.5">
                            <span className="text-[10px] font-mono text-slate-500">v{process.version}.0</span>
                            {process.isActive ? <NexBadge variant="emerald">Active</NexBadge> : <NexBadge variant="slate">Archived</NexBadge>}
                        </div>
                    </div>
                 </div>

                 {/* Definition Actions Menu */}
                 <div className="relative group/menu">
                    <button className="p-1 hover:bg-slate-100 rounded-sm text-slate-400"><MoreVertical size={16}/></button>
                    <div className="absolute right-0 top-6 w-40 bg-white border border-slate-200 shadow-xl rounded-sm z-20 hidden group-hover/menu:block py-1">
                        <button onClick={() => navigateTo('designer', process.id)} className="w-full text-left px-3 py-2 text-[10px] hover:bg-slate-50 flex items-center gap-2 text-slate-700 font-bold"><Edit size={12} className="text-blue-600"/> Edit Model</button>
                        <button onClick={() => handleGenerateDocs(process)} className="w-full text-left px-3 py-2 text-[10px] hover:bg-slate-50 flex items-center gap-2 text-slate-700"><BookOpen size={12}/> Generate Docs</button>
                        <button onClick={() => handleViewHistory(process)} className="w-full text-left px-3 py-2 text-[10px] hover:bg-slate-50 flex items-center gap-2 text-slate-700"><History size={12}/> Version History</button>
                        <div className="h-px bg-slate-100 my-1"></div>
                        <button onClick={() => handleDuplicate(process)} className="w-full text-left px-3 py-2 text-[10px] hover:bg-slate-50 flex items-center gap-2 text-slate-700"><Copy size={12}/> Duplicate</button>
                        <button onClick={() => toggleProcessState(process.id)} className="w-full text-left px-3 py-2 text-[10px] hover:bg-slate-50 flex items-center gap-2 text-slate-700"><PauseCircle size={12}/> {process.isActive ? 'Archive' : 'Activate'}</button>
                        <div className="h-px bg-slate-100 my-1"></div>
                        <button onClick={() => deleteProcess(process.id)} className="w-full text-left px-3 py-2 text-[10px] hover:bg-rose-50 flex items-center gap-2 text-rose-600"><Trash2 size={12}/> Delete</button>
                    </div>
                 </div>
              </div>

              <p className="text-xs text-slate-600 leading-relaxed mb-4 flex-1 line-clamp-3">
                {process.description || 'Enterprise grade workflow optimized for high-throughput and strict compliance adherence.'}
              </p>

              <div className="pt-4 border-t border-slate-100 flex items-center justify-between">
                <div className="flex items-center gap-3 text-[10px] font-bold text-slate-400">
                  <div className="flex items-center gap-1"><FileText size={12}/> {process.steps.length} Steps</div>
                  <div className="flex items-center gap-1"><Globe size={12}/> Global</div>
                </div>

                {process.isActive && (
                    <button 
                    onClick={() => handleStart(process.id)}
                    className="p-2 bg-slate-50 text-slate-600 border border-slate-200 rounded-sm hover:bg-blue-600 hover:text-white hover:border-blue-600 transition-all"
                    >
                    <Play size={14} fill="currentColor" />
                    </button>
                )}
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-sm border border-slate-300 shadow-sm overflow-hidden">
          <table className="w-full text-left border-collapse">
              <thead className="bg-slate-50 border-b border-slate-200">
                <tr className="text-[11px] font-bold text-slate-500 uppercase">
                  <th className="px-6 py-3 border-r border-slate-200">Instance ID</th>
                  <th className="px-6 py-3 border-r border-slate-200">Definition</th>
                  <th className="px-6 py-3 border-r border-slate-200">Status</th>
                  <th className="px-6 py-3 border-r border-slate-200">Started</th>
                  <th className="px-6 py-3 text-right">Control</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredInstances.length === 0 ? (
                    <tr><td colSpan={5} className="p-8 text-center text-xs text-slate-500 italic">No active runtimes matching criteria.</td></tr>
                ) : filteredInstances.map(inst => (
                    <tr key={inst.id} className="hover:bg-slate-50 transition-colors text-xs group">
                      <td className="px-6 py-3 font-mono text-slate-700 font-medium cursor-pointer hover:text-blue-600 underline" onClick={() => openInstanceViewer(inst.id)}>{inst.id}</td>
                      <td className="px-6 py-3 font-bold text-slate-800">{inst.definitionName}</td>
                      <td className="px-6 py-3">
                          <span className={`px-2 py-0.5 rounded-sm text-[10px] font-bold uppercase border ${
                            inst.status === 'Active' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' :
                            inst.status === 'Suspended' ? 'bg-amber-50 text-amber-700 border-amber-200' :
                            inst.status === 'Terminated' ? 'bg-rose-50 text-rose-700 border-rose-200' :
                            'bg-slate-100 text-slate-700 border-slate-200'
                          }`}>
                            {inst.status}
                          </span>
                      </td>
                      <td className="px-6 py-3 text-slate-600">
                          {new Date(inst.startDate).toLocaleDateString()}
                      </td>
                      <td className="px-6 py-3 text-right">
                          <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                              {inst.status === 'Active' && <button onClick={() => suspendInstance(inst.id)} title="Suspend" className="p-1 hover:bg-amber-100 text-amber-600 rounded"><PauseCircle size={14}/></button>}
                              {inst.status === 'Suspended' && <button onClick={() => suspendInstance(inst.id)} title="Resume" className="p-1 hover:bg-emerald-100 text-emerald-600 rounded"><Play size={14}/></button>}
                              {inst.status !== 'Terminated' && inst.status !== 'Completed' && <button onClick={() => terminateInstance(inst.id)} title="Terminate" className="p-1 hover:bg-rose-100 text-rose-600 rounded"><StopCircle size={14}/></button>}
                              <button onClick={() => openInstanceViewer(inst.id)} title="View" className="p-1 hover:bg-blue-100 text-blue-600 rounded"><Edit size={14}/></button>
                          </div>
                      </td>
                    </tr>
                ))}
              </tbody>
          </table>
        </div>
      )}

      {/* Version History Modal */}
      {selectedHistoryProc && (
          <NexModal isOpen={historyModalOpen} onClose={() => setHistoryModalOpen(false)} title={`History: ${selectedHistoryProc.name}`} size="xl">
              <div className="space-y-4">
                  {(!selectedHistoryProc.history || selectedHistoryProc.history.length === 0) ? (
                      <div className="p-8 text-center text-slate-400 italic">No previous versions available.</div>
                  ) : (
                      selectedHistoryProc.history.sort((a,b) => b.version - a.version).map(snap => (
                          <div key={snap.version} className="border border-slate-200 rounded-sm overflow-hidden mb-4">
                              <div className="p-3 bg-slate-50 border-b border-slate-200 flex justify-between items-center">
                                  <div>
                                      <span className="font-bold text-sm text-slate-800">Version {snap.version}.0</span>
                                      <span className="text-xs text-slate-500 ml-2">Deployed by {snap.author} on {new Date(snap.timestamp).toLocaleDateString()}</span>
                                  </div>
                                  <button className="text-xs font-bold text-blue-600 hover:underline">Revert to V{snap.version}</button>
                              </div>
                              <div className="h-64 relative">
                                  <ProcessDiffViewer oldVer={snap.definition as ProcessDefinition} newVer={selectedHistoryProc} />
                              </div>
                          </div>
                      ))
                  )}
              </div>
          </NexModal>
      )}

      {/* Documentation Modal */}
      <NexModal isOpen={docModalOpen} onClose={() => setDocModalOpen(false)} title="Process Documentation" size="xl">
          <div className="prose prose-sm max-w-none p-4" dangerouslySetInnerHTML={{ __html: docContent }} />
      </NexModal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { useBPM } from '../contexts/BPMContext';
import { Search, LayoutGrid, List as ListIcon, Briefcase, Layers, ChevronRight, CheckSquare } from 'lucide-react';
import { NexBadge } from './shared/NexUI';

interface SearchResultItem {
    id: string;
    title: string;
    description?: string;
    status: string;
    nexusType: 'Task' | 'Case' | 'Instance';
    assignee?: string;
    definitionName?: string;
}

export const TaskExplorer: React.FC = () => {
  const { tasks, cases, instances, globalSearch, navigateTo, openInstanceViewer } = useBPM();
  const [viewMode, setViewMode] = useState<'list' | 'grid'>('grid');
  const [searchTerm, setSearchTerm] = useState('');
  const [activeFilter, setActiveFilter] = useState<'All' | 'Tasks' | 'Cases' | 'Instances'>('All');

  useEffect(() => {
    if (globalSearch) setSearchTerm(globalSearch);
  }, [globalSearch]);

  const searchResults = useMemo<SearchResultItem[]>(() => {
    const s = searchTerm.toLowerCase();

    const taskMatches = tasks
      .filter(t => t.title.toLowerCase().includes(s) || t.description?.toLowerCase().includes(s))
      .map(t => ({ ...t, nexusType: 'Task' as const, description: t.description || 'Active task' }));

    const caseMatches = cases
      .filter(c => c.title.toLowerCase().includes(s) || c.description.toLowerCase().includes(s))
      .map(c => ({ ...c, nexusType: 'Case' as const, assignee: 'Case Owner' }));

    const instanceMatches = instances
      .filter(i => i.definitionName.toLowerCase().includes(s) || i.id.toLowerCase().includes(s))
      .map(i => ({ 
          id: i.id, 
          title: i.definitionName, 
          status: i.status, 
          nexusType: 'Instance' as const, 
          assignee: 'System',
          description: `Started ${new Date(i.startDate).toLocaleDateString()}`
      }));

    let combined = [...taskMatches, ...caseMatches, ...instanceMatches];

    if (activeFilter !== 'All') {
      combined = combined.filter(item => item.nexusType === activeFilter.slice(0, -1));
    }

    return combined;
  }, [searchTerm, tasks, cases, instances, activeFilter]);

  const handleNavigate = (item: SearchResultItem) => {
    if (item.nexusType === 'Task') navigateTo('inbox', item.id);
    else if (item.nexusType === 'Case') navigateTo('case-viewer', item.id);
    else if (item.nexusType === 'Instance') openInstanceViewer(item.id);
  };

  return (
    <div className="space-y-6 animate-fade-in pb-20">
       <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 border-b border-slate-300 pb-4">
          <div>
            <h2 className="text-xl font-bold text-slate-900 tracking-tight">Nexus Explorer</h2>
            <p className="text-xs text-slate-500 font-medium">Unified asset discovery.</p>
          </div>
          <div className="flex items-center gap-1 bg-slate-100 p-1 rounded-sm border border-slate-200">
             <button onClick={() => setViewMode('list')} className={`p-1.5 rounded-sm transition-all ${viewMode === 'list' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}><ListIcon size={16} /></button>
             <button onClick={() => setViewMode('grid')} className={`p-1.5 rounded-sm transition-all ${viewMode === 'grid' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}><LayoutGrid size={16} /></button>
          </div>
       </header>

       <div className="bg-white p-3 rounded-sm border border-slate-300 shadow-sm flex flex-col md:flex-row gap-3">
          <div className="relative flex-1 group">
             <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
             <input 
               type="text" 
               placeholder="Omni-search enterprise assets..." 
               value={searchTerm} 
               onChange={(e) => setSearchTerm(e.target.value)} 
               className="w-full pl-9 pr-3 py-2 bg-slate-50 border border-slate-200 rounded-sm text-xs font-medium focus:bg-white focus:border-blue-500 outline-none transition-all" 
             />
          </div>
          <div className="flex items-center gap-1">
             {['All', 'Tasks', 'Cases', 'Instances'].map(f => (
                <button 
                  key={f} 
                  onClick={() => setActiveFilter(f as any)} 
                  className={`px-3 py-2 rounded-sm text-[10px] font-bold uppercase transition-all border ${activeFilter === f ? 'bg-slate-800 text-white border-slate-800' : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50'}`}
                >
                  {f}
                </button>
             ))}
          </div>
       </div>

       <div className={`grid gap-4 ${viewMode === 'grid' ? 'grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1'}`}>
          {searchResults.map((item, idx) => (
             <div 
               key={`${item.id}-${idx}`} 
               onClick={() => handleNavigate(item)} 
               className={`bg-white rounded-sm border border-slate-300 shadow-sm hover:border-blue-400 hover:shadow-md transition-all flex flex-col group cursor-pointer ${viewMode === 'list' ? 'p-4 flex-row items-center gap-6' : 'p-4'}`}
             >
                <div className={`w-10 h-10 rounded-sm flex items-center justify-center shrink-0 border ${viewMode === 'list' ? 'mb-0' : 'mb-3'} ${
                   item.nexusType === 'Task' ? 'bg-blue-50 text-blue-600 border-blue-200' :
                   item.nexusType === 'Case' ? 'bg-amber-50 text-amber-600 border-amber-200' : 'bg-slate-800 text-white border-slate-900'
                }`}>
                   {item.nexusType === 'Task' ? <CheckSquare size={18}/> : item.nexusType === 'Case' ? <Briefcase size={18}/> : <Layers size={18}/>}
                </div>

                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <NexBadge variant={item.nexusType === 'Task' ? 'blue' : item.nexusType === 'Case' ? 'amber' : 'slate'}>{item.nexusType}</NexBadge>
                    <span className="text-[10px] text-slate-400 font-mono">{item.id.split('-')[1] || item.id}</span>
                  </div>
                  <h3 className="font-bold text-slate-900 text-sm mb-0.5 leading-tight truncate">
                    {item.title}
                  </h3>
                  <p className="text-[11px] text-slate-500 truncate">
                    {item.description || item.status}
                  </p>
                </div>

                <div className={`flex gap-2 ${viewMode === 'list' ? '' : 'mt-4 pt-3 border-t border-slate-100 justify-between items-center'}`}>
                   {viewMode === 'grid' && (
                     <div className="flex items-center gap-2">
                        <div className="w-6 h-6 rounded-sm bg-slate-100 flex items-center justify-center text-[9px] font-bold border border-slate-200">{item.assignee?.charAt(0) || 'S'}</div>
                        <span className="text-[10px] text-slate-600 font-bold truncate max-w-[80px]">{item.assignee || 'System'}</span>
                     </div>
                   )}
                   <ChevronRight size={16} className="text-slate-300 group-hover:text-blue-600 transition-colors" />
                </div>
             </div>
          ))}
          {searchResults.length === 0 && (
             <div className="col-span-full py-20 text-center bg-white rounded-sm border border-slate-200">
                <Search size={32} className="mx-auto text-slate-300 mb-4" />
                <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">No artifacts found.</p>
             </div>
          )}
       </div>
    </div>
  );
};

import React, { useEffect, useRef } from 'react';
import { 
  Copy, Trash2, Link2Off, Settings, 
  Plus, Play, GitBranch, Crosshair, 
  ClipboardPaste, Eraser, Clipboard
} from 'lucide-react';

interface ContextMenuProps {
  position: { x: number; y: number } | null;
  targetId: string | null;
  onClose: () => void;
  onAction: (action: string, payload?: unknown) => void;
}

interface MenuItemProps {
    icon: React.ElementType;
    label: string;
    action: string;
    payload?: unknown;
    shortcut?: string;
    danger?: boolean;
    onClick: (e: React.MouseEvent, action: string, payload?: unknown) => void;
}

const MenuItem: React.FC<MenuItemProps> = ({ icon: Icon, label, action, payload, shortcut, danger, onClick }) => (
  <button 
    type="button"
    onClick={(e) => onClick(e, action, payload)}
    className={`w-full flex items-center justify-between px-3 py-2 text-xs text-left transition-colors group ${danger ? 'hover:bg-rose-50 text-rose-700' : 'hover:bg-blue-50 text-slate-700'}`}
  >
    <div className="flex items-center gap-2">
      <Icon size={14} className={danger ? 'text-rose-500' : 'text-slate-400 group-hover:text-blue-600'} />
      <span className="font-medium">{label}</span>
    </div>
    {shortcut && <span className="text-[10px] text-slate-400 font-mono ml-4">{shortcut}</span>}
  </button>
);

const Divider = () => <div className="h-px bg-slate-100 my-1" />;

export const CanvasContextMenu: React.FC<ContextMenuProps> = ({ position, targetId, onClose, onAction }) => {
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        onClose();
      }
    };
    document.addEventListener('mousedown', handleClickOutside, true);
    return () => document.removeEventListener('mousedown', handleClickOutside, true);
  }, [onClose]);

  if (!position) return null;

  const handleItemClick = (e: React.MouseEvent, action: string, payload?: unknown) => {
    e.preventDefault();
    e.stopPropagation(); 
    onAction(action, payload);
    onClose();
  };

  return (
    <div 
      ref={menuRef}
      onMouseDown={(e) => e.stopPropagation()} 
      className="fixed z-dropdown bg-white border border-slate-200 rounded-sm shadow-xl min-w-[180px] animate-fade-in flex flex-col py-1"
      style={{ top: position.y, left: position.x }}
    >
      {targetId ? (
        <>
          <div className="px-3 py-1.5 text-[10px] font-bold text-slate-400 uppercase tracking-wider border-b border-slate-100 mb-1">
            Component Options
          </div>
          <MenuItem icon={Settings} label="Properties" action="edit" onClick={handleItemClick} />
          <MenuItem icon={Clipboard} label="Copy" action="copy" shortcut="Ctrl+C" onClick={handleItemClick} />
          <MenuItem icon={Copy} label="Duplicate" action="duplicate" shortcut="Ctrl+D" onClick={handleItemClick} />
          <MenuItem icon={Link2Off} label="Disconnect" action="disconnect" onClick={handleItemClick} />
          <Divider />
          <MenuItem icon={Trash2} label="Delete" action="delete" danger shortcut="Del" onClick={handleItemClick} />
        </>
      ) : (
        <>
          <div className="px-3 py-1.5 text-[10px] font-bold text-slate-400 uppercase tracking-wider border-b border-slate-100 mb-1">
            Canvas Actions
          </div>
          <MenuItem icon={ClipboardPaste} label="Paste Component" action="paste" shortcut="Ctrl+V" onClick={handleItemClick} />
          <Divider />
          <MenuItem icon={Plus} label="Add User Task" action="add-node" payload="user-task" onClick={handleItemClick} />
          <MenuItem icon={GitBranch} label="Add Gateway" action="add-node" payload="exclusive-gateway" onClick={handleItemClick} />
          <MenuItem icon={Play} label="Add Start Event" action="add-node" payload="start" onClick={handleItemClick} />
          <Divider />
          <MenuItem icon={Crosshair} label="Reset View" action="reset-view" onClick={handleItemClick} />
          <MenuItem icon={Eraser} label="Clear Canvas" action="clear-canvas" danger onClick={handleItemClick} />
        </>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { ProcessStepType } from '../../types';
import { getStepTypeMetadata, STEP_CATEGORIES } from './designerUtils';
import { Plus, ChevronDown, ChevronRight, Search } from 'lucide-react';

interface PaletteItemProps {
  type: ProcessStepType;
  onAdd: (type: ProcessStepType) => void;
}

const PaletteItem: React.FC<PaletteItemProps> = ({ type, onAdd }) => {
  const { icon: Icon, color, defaultName: label } = getStepTypeMetadata(type);

  const onDragStart = (event: React.DragEvent<HTMLDivElement>, nodeType: string) => {
    event.dataTransfer.setData('application/reactflow', nodeType);
    event.dataTransfer.effectAllowed = 'move';
  };

  return (
    <div 
      className="flex items-center group relative"
      draggable 
      onDragStart={(e) => onDragStart(e, type)}
    >
        <button 
        onClick={() => onAdd(type)} 
        className="w-full flex items-center gap-3 p-2 bg-white hover:bg-slate-50 border border-transparent hover:border-slate-200 rounded-sm text-left transition-all cursor-grab active:cursor-grabbing"
        >
        <div className={`w-8 h-8 rounded-sm flex items-center justify-center shrink-0 bg-slate-50 border border-slate-200 group-hover:bg-white group-hover:border-blue-400`}>
            <Icon size={16} className={`${color} group-hover:text-blue-600`} />
        </div>
        <div className="flex-1 min-w-0">
            <span className="block text-xs font-bold text-slate-700 truncate">{label}</span>
        </div>
        <Plus size={14} className="text-slate-300 group-hover:text-blue-50 opacity-0 group-hover:opacity-100" />
        </button>
    </div>
  );
};

export const PaletteSidebar = ({ onAddNode }: { onAddNode: (type: ProcessStepType) => void }) => {
  const [openCategories, setOpenCategories] = useState<string[]>(['Core', 'Communication', 'AI & ML']);
  const [search, setSearch] = useState('');

  const toggleCategory = (cat: string) => {
    setOpenCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat]);
  };

  const groupedSteps: Record<string, ProcessStepType[]> = {};

  const allTypes: ProcessStepType[] = [
    'start', 'end', 'user-task', 'service-task', 'sub-process', 'script-task',
    'exclusive-gateway', 'parallel-gateway', 'inclusive-gateway', 'complex-gateway', 'event-gateway',
    'timer-event', 'message-event', 'signal-event', 'error-event', 'escalation-event', 'compensation-event',
    'email-send', 'slack-post', 'teams-message', 'sms-twilio', 'whatsapp-msg', 'push-notification', 'sendgrid-email', 'mailchimp-add',
    'pdf-generate', 'doc-sign', 'ocr-extract', 's3-upload', 'gdrive-save', 'sharepoint-store', 'dropbox-save', 'template-render',
    'salesforce-create', 'salesforce-update', 'hubspot-add', 'zoho-lead', 'pipedrive-deal', 'dynamics-record', 'zendesk-ticket', 'intercom-msg',
    'jira-issue', 'github-pr', 'gitlab-merge', 'bitbucket-commit', 'trello-card', 'asana-task', 'linear-issue', 'pagerduty-alert',
    'aws-lambda', 'azure-func', 'gcp-function', 'kubernetes-job', 'vm-provision', 'db-provision', 'dns-update', 'cdn-purge',
    'sql-query', 'rest-api', 'graphql-query', 'soap-call', 'kafka-publish', 'rabbit-mq', 'ftp-upload', 'csv-parse', 'xml-transform', 'json-map',
    'ai-text-gen', 'ai-summarize', 'ai-sentiment', 'ai-vision', 'ai-translate', 'ai-classify', 'automl-predict', 'vector-embed',
    'stripe-charge', 'paypal-payout', 'quickbooks-invoice', 'xero-bill', 'sap-posting', 'oracle-ledger', 'expensify-report',
    'business-rule', 'decision-table', 'wait-state', 'terminate-end', 'loop-container'
  ];

  allTypes.forEach(type => {
    const meta = getStepTypeMetadata(type);
    if (!groupedSteps[meta.category]) groupedSteps[meta.category] = [];
    if (meta.defaultName.toLowerCase().includes(search.toLowerCase()) || meta.category.toLowerCase().includes(search.toLowerCase())) {
        groupedSteps[meta.category].push(type);
    }
  });

  return (
    <aside className="w-full h-full bg-slate-50 border-r border-slate-300 flex flex-col shrink-0">
      <div className="border-b border-slate-200" style={{ padding: 'var(--space-base)' }}>
        <h2 className="text-xs font-bold text-slate-800 uppercase tracking-wider mb-2">Component Library</h2>
        <div className="relative">
            <Search className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" size={12}/>
            <input 
                className="w-full pl-7 pr-2 py-1.5 bg-white border border-slate-300 rounded-sm text-xs outline-none focus:border-blue-500" 
                placeholder="Search components..."
                value={search}
                onChange={e => setSearch(e.target.value)}
            />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto no-scrollbar" style={{ padding: 'var(--space-base)', gap: 'var(--space-base)', display: 'flex', flexDirection: 'column' }}>
        {STEP_CATEGORIES.map(category => {
            const steps = groupedSteps[category] || [];
            if (steps.length === 0) return null;

            const isOpen = openCategories.includes(category) || search.length > 0;

            return (
                <div key={category} className="mb-2">
                    <button 
                        onClick={() => toggleCategory(category)}
                        className="w-full flex items-center justify-between px-2 py-1.5 text-[10px] font-bold text-slate-500 uppercase hover:bg-slate-100 rounded-sm transition-colors"
                    >
                        <span>{category}</span>
                        {isOpen ? <ChevronDown size={12}/> : <ChevronRight size={12}/>}
                    </button>

                    {isOpen && (
                        <div className="mt-1 space-y-0.5 pl-1 animate-slide-up">
                            {steps.map(type => (
                                <PaletteItem key={type} type={type} onAdd={onAddNode} />
                            ))}
                        </div>
                    )}
                </div>
            );
        })}
      </div>
    </aside>
  );
};

import React, { memo, useMemo } from 'react';
import { Handle, Position, NodeProps } from 'reactflow';
import { ProcessStep } from '../../types';
import { getStepTypeMetadata } from './designerUtils';
import { FunctionSquare, RefreshCw, Code, Layers, ShieldAlert } from 'lucide-react';
import { validateStepConfiguration } from './stepSchemas';

interface CustomNodeData {
  step: ProcessStep;
}

export const NodeComponent = memo(({ data, selected }: NodeProps<CustomNodeData>) => {
  const { step } = data;
  const { icon: Icon, color } = getStepTypeMetadata(step.type);

  const hasRule = !!step.businessRuleId;
  const hasScript = !!step.onEntryAction || !!step.onExitAction;
  const hasRetry = step.retryPolicy?.enabled;
  const isLoop = step.isMultiInstance;

  const isValid = useMemo(() => validateStepConfiguration(step.type, step.data), [step.type, step.data]);

  return (
    <div 
      className={`w-[200px] h-[80px] border flex flex-col shadow-sm transition-shadow select-none group ${
        selected 
          ? 'border-active ring-2 ring-blue-500/20 shadow-md' 
          : (isValid ? 'border-default hover:border-tertiary' : 'border-rose-300 ring-1 ring-rose-200')
      }`} 
      style={{ 
        borderRadius: 'var(--radius-base)',
        backgroundColor: 'var(--component-bg)',
      }}
    >
      <Handle 
        type="target" 
        position={Position.Left} 
        className="!bg-slate-400 !w-2.5 !h-2.5 !-left-1.5 hover:!bg-blue-600 transition-colors" 
        style={{ borderColor: 'var(--component-bg)', borderWidth: '2px' }}
      />

      <div className="flex items-center gap-3 px-3 pt-3 pb-1 flex-1 overflow-hidden pointer-events-none">
        <div className={`w-8 h-8 flex items-center justify-center rounded-base bg-subtle border border-default relative shrink-0`}>
          <Icon size={16} className={color.replace('text-', 'text-opacity-80 text-')} />
          {!isValid && (
             <div className="absolute -top-1.5 -right-1.5 bg-white rounded-full p-0.5 shadow-sm" title="Invalid Configuration">
                <ShieldAlert size={14} className="text-rose-500 fill-rose-50"/>
             </div>
          )}
        </div>

        <div className="flex-1 min-w-0">
          <p className="text-[12px] font-bold text-primary truncate leading-tight">
            {step.name}
          </p>
          <p className="text-[10px] text-secondary uppercase tracking-wide truncate mt-0.5">
            {step.type.replace(/-/g, ' ')}
          </p>
        </div>
      </div>

      {(hasRule || hasScript || hasRetry || isLoop) && (
          <div className="px-3 pb-2 flex gap-1.5 items-center pointer-events-none">
              {hasRule && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-indigo-50 border border-indigo-100 rounded-[2px] text-[8px] font-bold text-indigo-700">
                      <FunctionSquare size={8} /> RULE
                  </div>
              )}
              {hasScript && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-amber-50 border border-amber-100 rounded-[2px] text-[8px] font-bold text-amber-700">
                      <Code size={8} /> FN
                  </div>
              )}
              {hasRetry && (
                  <div className="flex items-center gap-0.5 px-1 py-0.5 bg-blue-50 border border-blue-100 rounded-[2px] text-[8px] font-bold text-blue-700">
                      <RefreshCw size={8} /> {step.retryPolicy?.maxAttempts}x
                  </div>
              )}
              {isLoop && (
                  <div className="ml-auto text-secondary">
                      <Layers size={10} />
                  </div>
              )}
          </div>
      )}

      <Handle 
        type="source" 
        position={Position.Right} 
