                    </NexFormGroup>
                );
            case 'textarea':
            case 'json':
            case 'code':
                return (
                    <NexFormGroup key={field.key} label={field.label} helpText={field.helpText}>
                        <textarea 
                            className={`prop-input min-h-[100px] resize-y ${field.type === 'code' || field.type === 'json' ? 'font-mono text-[10px]' : ''}`}
