    const loadTestCase = (tc: TestCase) => {
        setInputData(tc.input);
    };

    const saveTestCase = () => {
        if (!saveName) return;
        setTestCases([...testCases, { id: `tc-${Date.now()}`, name: saveName, input: inputData }]);
        setSaveName('');
    };

    return (
        <div className="flex flex-col h-full bg-subtle border-l border-default">
